#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void scale_shift(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 scale = 3;
    const int16 shift_val = 100;
    const unsigned samples = 64;

    for (unsigned i = 0; i < samples; i += 8) {
        aie::vector<int16, 8> x = readincr_v<8>(in);
        aie::vector<int16, 8> scale_vec = aie::broadcast<int16, 8>(scale);
        aie::accum<acc48, 16> acc = aie::mul(x, scale_vec);
        aie::vector<int16, 8> prod = acc.to_vector<int16>(0);
        aie::vector<int16, 8> shift_vec = aie::broadcast<int16, 8>(shift_val);
        aie::vector<int16, 8> result = aie::add(prod, shift_vec);
        writeincr_v<8>(out, result);
    }
}

