#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

static const int WINDOW_LEN  = 4;
static const int NUM_SAMPLES = 32;
static const int SCALE_SHIFT = 2;

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
    // Using int16 for delay line to save memory
    int16 delay[WINDOW_LEN] = {0, 0, 0, 0};

    for (int i = 0; i < NUM_SAMPLES; i++)
    chess_prepare_for_pipelining
    {
        int32 sample = readincr(in);

        // Shift delay line
        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];
        delay[0] = (int16)sample;

        // Vectorized accumulation: int16 vector with int32 vector multiply
        aie::vector<int16, 4> v16 = aie::load_v<4>((int16*)delay);
        aie::vector<int32, 4> v32 = aie::broadcast<int32, 4>(1);

        // Element type mismatch: int16 * int32 not allowed
        aie::vector<int32, 4> prod = aie::mul(v16, v32);

        // Horizontal sum
        int32 acc = prod[0] + prod[1] + prod[2] + prod[3];

        int32 result = acc >> SCALE_SHIFT;
        writeincr(out, result);
    }
}

