#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void clip_threshold(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t threshold = 1000;
    const int32_t neg_clip = -2000;
    const int32_t pos_clip = 2000;

    aie::accum<acc48, 16> acc = aie::zeros<acc48, 16>();

    for (int i = 0; i < 64; i++) {
        aie::vector<int32_t, 8> vec = readincr_v<8>(in);
        aie::vector<int32_t, 8> result;

        for (int j = 0; j < 8; j++) {
            int32_t val = vec[j];
            int32_t out_val;

            if (val > threshold) {
                out_val = pos_clip;
            } else if (val < -threshold) {
                out_val = neg_clip;
            } else {
                out_val = val;
            }
            result[j] = out_val;
        }

        acc = aie::mac(acc, result, aie::broadcast<int32_t, 16>(1));
        writeincr_v<8>(out, result);
    }
}

