#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void scale_shift(input_window<uint16>* in, output_window<uint16>* out) {
    // Scale factor: multiply by 3, add offset 128
    const uint16_t scale = 3;
    const uint16_t offset = 128;
    const uint32_t num_samples = 256;

    auto in_iter = aie::begin(*in);
    auto out_iter = aie::begin(*out);

    for (uint32_t i = 0; i < num_samples; i++) {
        chess_prepare_for_pipelining
        uint16_t val = *in_iter++;
        // Explicit intermediate to allow mutation of operator precedence
        uint32_t scaled = (uint32_t)val * scale;
        uint32_t shifted = scaled + offset;
        // Saturate to uint16 range
        uint16_t result = (shifted > 0xFFFF) ? 0xFFFF : (uint16_t)shifted;
        *out_iter++ = result;
    }
}

