#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* sin, output_stream<uint16>* sout) {
  const int16 coeffs[4] = {1, 2, 3, 4};
  const int shift = 4;
  const unsigned samples = 64;

  uint16 delay[4] = {0, 0, 0, 0};
  unsigned idx = 0;

  for (unsigned i = 0; i < samples; i++) {
    uint16 x = readincr(sin);
    delay[idx] = x;

    int32 acc = 0;
    for (unsigned tap = 0; tap < 4; tap++) {
      unsigned d = (idx + 1 + tap) & 3;
      acc += int32(delay[d]) * int32(coeffs[tap]);
    }

    uint16 y = uint16(acc >> shift);
    writeincr(sout, y);

    idx = (idx + 1) & 3;
  }
}

