  }

  for (int n = 0; n < 64; n++) {
    aie::accum<acc48, 8> acc = aie::zeros<acc48, 8>();
    acc = aie::mul(history, aie::broadcast<float, 8>(1.0f));
    float avg = aie::srs(acc, 3)[0];
    writeincr(out, avg);

    for (int i = 0; i < window_size - 1; i++) {
      history[i] = history[i + 1];
    }
    history[window_size - 1] = readincr(in);
  }
}

