#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

// Decimation by factor D: keep every D-th sample
// Explicit semantic choice: decimation factor
static const int DECIM_FACTOR = 4;
static const int BLOCK_SIZE = 64;

void decimate_kernel(input_window<int32_t>* in, output_window<int32_t>* out) {
    auto in_iter = aie::begin(in);
    auto out_ptr = aie::begin(out);

    // Phase counter: which sample to keep (0 = keep, 1..D-1 = discard)
    int phase = 0;

    for (int i = 0; i < BLOCK_SIZE; i++) {
        int32_t sample = *in_iter++;

        if (phase == 0) {
            *out_ptr++ = sample;
        }

        phase = phase + 1;
        if (phase >= DECIM_FACTOR) {
            phase = 0;
        }
    }
}

