void scale_shift_kernel(input_stream<uint16>* in, output_stream<uint16>* out) {
    // Process 256 samples per invocation
    const int32_t NUM_SAMPLES = 256;

    // Scaling factor: multiply by 3/4 then add offset 16
    const uint16_t SCALE_NUM = 3;
    const uint16_t SCALE_DEN = 4;
    const uint16_t OFFSET = 16;

    // Process 7 samples at a time using vectorized read
    const int32_t VEC_SIZE = 7;

    for (int32_t i = 0; i < NUM_SAMPLES / VEC_SIZE; i++) {
        aie::vector<uint16, VEC_SIZE> vec = readincr_v<VEC_SIZE>(in);

        for (int32_t j = 0; j < VEC_SIZE; j++) {
            uint16_t val = vec[j];

            // Scale: val * 3 / 4
            uint32_t prod = (uint32_t)val * SCALE_NUM;
            uint16_t scaled = (uint16_t)(prod / SCALE_DEN);

            // Add offset with saturation
            uint32_t result = (uint32_t)scaled + OFFSET;
            if (result > 65535) result = 65535;

            writeincr(out, (uint16_t)result);
        }
    }
}

