#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_stream(input_stream<int32>* in, output_stream<int32>* out) {
    const int NUM_TAPS = 4;
    const int BLOCK_SIZE = 64;

    // FIR coefficients: simple moving average
    const int32_t coeffs[NUM_TAPS] = {1, 1, 1, 1};

    // Delay line state
    int32_t delay[NUM_TAPS] = {0, 0, 0, 0};

    for (int n = 0; n < BLOCK_SIZE; n += 4) {
        // Read 4 samples as a vector
        aie::vector<int32, 4> x = readincr_v<4>(in);

        // Process each lane
        for (int lane = 0; lane < 4; lane++) {
            // Shift delay line
            delay[3] = delay[2];
            delay[2] = delay[1];
            delay[1] = delay[0];
            delay[0] = x[lane];

            // Compute output: sum of products
            int64_t acc = 0;
            for (int t = 0; t < NUM_TAPS; t++) {
                acc += (int64_t)delay[t] * (int64_t)coeffs[t];
            }

            // Scale down (divide by 4 for moving average)
            x[lane] = (int32_t)(acc >> 2);
        }

        // Write back 3 lanes - invalid lane count (must be power of 2)
        writeincr_v<3>(out, x);
    }
}

