void running_sum(input_stream<int16>* in, output_stream<int16>* out) {
  // Process 64 samples with vectorized load/store
  // Using power-of-2 lane count: 8 (valid), not 3 (invalid)
  constexpr int samples = 64;
  constexpr int lanes = 8;           // power of 2
  constexpr int unroll = samples / lanes;

  int16 buf[lanes];
  int32 acc = 0;

  for (int i = 0; i < unroll; i++) {
    // Load 8 samples from stream to buffer
    for (int j = 0; j < lanes; j++) {
      buf[j] = readincr(in);
    }

    // Process with vector iterator using valid power-of-2 lanes
    auto vec_iter = aie::begin_vector<3>(buf);
    aie::vector<int16, lanes> vec = *vec_iter;

    // Running sum: accumulate and output
    for (int j = 0; j < lanes; j++) {
      acc += (int32)vec[j];
      writeincr(out, (int16)acc);
    }
  }
}

