#include <aie_api/aie_adf.hpp>

#define WINDOW_SIZE 4
#define NUM_ITERATIONS 64

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
    aie::vector<int32, 4> state = aie::zeros<int32, 4>();
    int32 phase = 0;

    for (int n = 0; n < NUM_ITERATIONS; n++) {
        int32 sample = readincr(in);

        state[phase] = sample;

        aie::accum<acc80, 4> acc = aie::zeros<acc80, 4>();
        acc = aie::mac(acc, state, aie::broadcast<int32, 4>(1));

        int32 result = aie::srs(acc, 2)[0];

        writeincr(out, result);

        phase = (phase + 1) & (WINDOW_SIZE - 1);
    }
}

