        delay_line[3] = delay_line[2];
        delay_line[2] = delay_line[1];
        delay_line[1] = delay_line[0];
        delay_line[0] = sample;

        aie::accum<acc48, 4> acc = aie::zeros<acc48, 4>();
        aie::vector<uint16_t, 4> dvec;
        dvec[0] = delay_line[0];
        dvec[1] = delay_line[1];
        dvec[2] = delay_line[2];
        dvec[3] = delay_line[3];
        aie::vector<uint16_t, 4> tvec;
        tvec[0] = taps[0];
        tvec[1] = taps[1];
        tvec[2] = taps[2];
        tvec[3] = taps[3];

        acc = aie::mul(dvec, tvec);
        uint16_t result = acc.to_vector<uint16_t>(scale_shift)[0];
        writeincr(out, result);
    }
}

