#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void threshold_clip(input_stream<int16>* __restrict in, output_stream<int16>* __restrict out) {
    const int16 THRESHOLD = 1000;
    const int16 CLIP_HIGH = 32767;
    const int16 CLIP_LOW = -32768;
    const int32 NUM_SAMPLES = 64;

    for (int32 i = 0; i < NUM_SAMPLES; i++) {
        chess_prepare_for_pipelining
        int16 sample = readincr(in);
        int16 result;

        int32 abs_val = sample;
        if (abs_val < 0) {
            abs_val = -abs_val;
        }

        if (abs_val > THRESHOLD) {
            if (sample > 0) {
                result = CLIP_HIGH;
            } else {
                result = CLIP_LOW;
            }
        } else {
            result = sample;
        }

        writeincr(out, result);
    }
}

