void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    const unsigned num_taps = 4;
    const uint16_t coeffs[num_taps] = {1, 2, 3, 4};
    uint16_t delay_line[num_taps] = {0, 0, 0, 0};
    unsigned tap_idx = 0;

    const unsigned num_samples = 64;

    for (unsigned n = 0; n < num_samples; n += 4) {
        aie::vector<uint16_t, 4> sample_vec = readincr_v<4>(in);

