            delay_line[tap_idx] = sample;

            uint32_t acc = 0;
            for (unsigned i = 0; i < num_taps; i++) {
                unsigned idx = (tap_idx + num_taps - i) % num_taps;
                acc += (uint32_t)delay_line[idx] * (uint32_t)coeffs[i];
            }

            uint16_t result = (uint16_t)(acc >> 4);
            writeincr(out, result);

            tap_idx = (tap_idx + 1) % num_taps;
        }
    }
}

