void fir_filter(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t taps[4] = {1, 2, 3, 4};
    const int shift_bits = 0;
    const int num_samples = 64;

    alignas(16) int32_t delay_line[4] = {0, 0, 0, 0};

