#include <adf.h>

void prefix_sum(input_stream<int16_t>* in, output_stream<int16_t>* out) {
  constexpr int32_t NUM_SAMPLES = 128;
  constexpr int32_t VECTOR_LANES = 16;

  int16_t buf[NUM_SAMPLES];
  int32_t running_sum = 0;

  // Read all input samples
  for (int32_t i = 0; i < NUM_SAMPLES; i++) {
    buf[i] = readincr(in);
  }

  // Compute prefix sums with explicit scaling factor
  constexpr int16_t SCALE_NUM = 1;
  constexpr int16_t SCALE_DEN = 1;

  for (int32_t i = 0; i < NUM_SAMPLES; i += VECTOR_LANES) {
    aie::vector<int16_t, VECTOR_LANES> vin = aie::load_v<VECTOR_LANES>(&buf[i]);
    aie::vector<int16_t, VECTOR_LANES> vout;

    for (int32_t lane = 0; lane < VECTOR_LANES; lane++) {
      running_sum += vin[lane];
      int32_t scaled = (running_sum * SCALE_NUM) / SCALE_DEN;
      // Saturate to int16 range
      if (scaled > 32767) scaled = 32767;
      if (scaled < -32768) scaled = -32768;
      vout[lane] = (int16_t)scaled;
    }

    aie::store_v(&buf[i], vout);
  }

  // Write output samples
  for (int32_t i = 0; i < NUM_SAMPLES; i++) {
    writeincr(out, buf[i]);
  }
}

