#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int16>* sin, output_stream<int16>* sout) {
    const int TAPS = 4;
    const int SHIFT = 15;
    const int32_t COEFF[TAPS] = {16384, 32767, 32767, 16384}; // Q15 normalized

    int16 delay_line[TAPS] = {0};

    for (int n = 0; n < 128; n++) {
        int16 sample = readincr(sin);

        // Shift delay line
        for (int i = TAPS - 1; i > 0; i--) {
            delay_line[i] = delay_line[i - 1];
        }
        delay_line[0] = sample;

        // MAC accumulation
        int64_t acc = 0;
        for (int i = 0; i < TAPS; i++) {
            acc += (int32_t)delay_line[i] * COEFF[i];
        }

        // Scale and saturate
        int32_t scaled = (int32_t)(acc >> SHIFT);
        if (scaled > 32767) scaled = 32767;
        if (scaled < -32768) scaled = -32768;

        writeincr(sout, (int16)scaled);
    }
}

