#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
    constexpr int32_t WINDOW_SIZE = 4;
    constexpr int32_t ITERATIONS = 64;
    aie::vector<int32, 4> buffer = aie::zeros<int32, 4>();
    aie::vector<int32, 4> weights = aie::broadcast<int32, 4>(1);
    int32_t sum = 0;

    for (int32_t i = 0; i < WINDOW_SIZE - 1; i++) {
        buffer[i] = readincr(in);
        sum += buffer[i];
    }

    for (int32_t i = 0; i < ITERATIONS; i++) {
        int32_t new_sample = readincr(in);
        aie::store_v(buffer.data(), aie::load_v<4>(buffer.data() + 1));
        buffer[WINDOW_SIZE - 1] = new_sample;
        sum = 0;
        aie::accum<acc80, 4> acc = aie::mul(buffer, weights);
        sum = acc.to_vector<int32>(0)[0] + acc.to_vector<int32>(0)[1] + 
              acc.to_vector<int32>(0)[2] + acc.to_vector<int32>(0)[3];
        int32_t avg = sum / WINDOW_SIZE;
        writeincr(out, avg);
    }
