// Moving average filter with explicit window size as named constant
static const int WINDOW_SIZE = 4;
static const int NUM_ITERATIONS = 128;

void moving_avg(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    // Delay line state - explicitly named for mutation potential
    int32_t delay_line[WINDOW_SIZE] = {0, 0, 0, 0};
    int32_t delay_index = 0;

    for (int n = 0; n < NUM_ITERATIONS; n++) {
        // Read new sample using wrong API: readincr_v<1> instead of readincr
