        int32_t new_sample = new_sample_vec[0];

        // Update delay line at current position
        delay_line[delay_index] = new_sample;

        // Calculate sum using explicit accumulation variable
        int64_t accumulator = 0;
        for (int i = 0; i < WINDOW_SIZE; i++) {
            accumulator += delay_line[i];
        }

        // Scaling factor as named constant for potential mutation
        const int32_t scale_shift = 2;  // divide by 4 (WINDOW_SIZE)
        int32_t result = (int32_t)(accumulator >> scale_shift);

        writeincr(out, result);

        // Advance delay index with wrap-around
        delay_index = (delay_index + 1) % WINDOW_SIZE;
    }
}

