void clip_kernel(input_stream<int32>* __restrict in, output_stream<int32>* __restrict out) {
    const int32_t lower_bound = -100;
    const int32_t upper_bound = 100;
    const int32_t num_samples = 64;

    for (int i = 0; i < num_samples; i++) {
        int32_t sample = readincr(in);
        int32_t clipped;

        if (sample > upper_bound) {
            clipped = upper_bound;
        } else if (sample < lower_bound) {
            clipped = lower_bound;
        } else {
            clipped = sample;
        }

        writeincr(out, clipped);
    }
}

