#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

static const int WINDOW_LEN  = 4;
static const int NUM_SAMPLES = 32;
static const int SCALE_SHIFT = 2; // divide by WINDOW_LEN=4 via right shift

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
    int32 delay[WINDOW_LEN] = {0, 0, 0, 0};

    for (int i = 0; i < NUM_SAMPLES; i++)
    chess_prepare_for_pipelining
    {
        int32 sample = readincr(in);

        // Shift delay line
        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];
        delay[0] = sample;

        // Vectorized accumulation with mismatched element types
        aie::vector<int16, 4> v16 = aie::broadcast<int16, 4>(1);
        aie::vector<int32, 4> v32 = aie::broadcast<int32, 4>(1);
        aie::vector<int32, 4> prod = aie::mul(v16, v32);

        // Accumulate window using int32 arithmetic
        int32 acc = delay[0] + delay[1] + delay[2] + delay[3];

        // Scale by right shift (divide by WINDOW_LEN)
        int32 result = acc >> SCALE_SHIFT;

        writeincr(out, result);
    }
}

