void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
  // 4-tap FIR coefficients as int16 vector
  aie::vector<int16, 4> coeff = {1, 2, 3, 4};

  // Delay line for uint16 samples
  uint16 delay_line[4] = {0, 0, 0, 0};
  int tap_idx = 0;

  const int samples = 64;

  for (int n = 0; n < samples; ++n) {
    uint16 sample = readincr(in);

    // Insert new sample into delay line
    delay_line[tap_idx] = sample;

    // Load delay line samples as int32 vector
    aie::vector<int32, 4> data;
    for (int i = 0; i < 4; ++i) {
      int idx = (tap_idx - i) & 3;
      data[i] = static_cast<int32>(delay_line[idx]);
    }

    // Direct multiplication of int16 and int32 vectors - type mismatch
    aie::vector<int32, 4> prod = coeff * data;

    // Sum the products
    int32 acc = prod[0] + prod[1] + prod[2] + prod[3];

    // Scale down and saturate to uint16
    uint16 result = static_cast<uint16>((acc >> 3) & 0xFFFF);
    writeincr(out, result);

    tap_idx = (tap_idx + 1) & 3;
  }
}

