#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_int32(input_stream<int32>* in, output_stream<int32>* out) {
    const int32_t taps[4] = {1, 2, 3, 4};
    const int32_t shift = 0;
    const int samples = 64;

    int32_t delay_line[4] = {0, 0, 0, 0};

    for (int n = 0; n < samples; n++) {
        int32_t x = readincr(in);

        delay_line[3] = delay_line[2];
        delay_line[2] = delay_line[1];
        delay_line[1] = delay_line[0];
        delay_line[0] = x;

        aie::accum<acc48, 4> acc = aie::zeros<acc48, 4>();
        aie::vector<int32, 4> data = aie::load_v<4>(delay_line);
        aie::vector<int32, 4> coeff = aie::load_v<4>(taps);

        acc = aie::mac(acc, data, coeff);

        int32_t sum = acc.to_vector<int32>(shift)[0] + acc.to_vector<int32>(shift)[1]
                    + acc.to_vector<int32>(shift)[2] + acc.to_vector<int32>(shift)[3];

        writeincr(out, sum);
    }
