#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 taps[4] = {1, 2, 3, 4};
    const int taps_len = 4;
    const int samples = 64;

    int16 delay_line[4] = {0, 0, 0, 0};

    for (int n = 0; n < samples; n++) {
        int16 sample = readincr(in);

        // Shift delay line
        for (int i = taps_len - 1; i > 0; i--) {
            delay_line[i] = delay_line[i-1];
        }
        delay_line[0] = sample;

        // Compute FIR output
        int32 accum = 0;
        for (int i = 0; i < taps_len; i++) {
            accum += (int32)delay_line[i] * (int32)taps[i];
        }

        // Scale down and saturate to int16
        int16 output = (int16)(accum >> 4);
        writeincr(out, output);
    }
}

