void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
  const int window_size = 8;
  aie::vector<float, 8> coeffs = aie::broadcast<float, 8>(1.0f / window_size);

  aie::vector<int32, 8> history;
  for (int i = 0; i < 8; i++) {
    history[i] = readincr(in);
  }

  for (int n = 0; n < 64; n++) {
    aie::vector<float, 8> hist_f = aie::vector<float, 8>(history);
    aie::accum<acc48, 8> acc = aie::mul(coeffs, hist_f);
    int32 avg = aie::srs(acc, 0)[0];
    writeincr(out, avg);

    for (int i = 0; i < 7; i++) {
      history[i] = history[i + 1];
    }
    history[7] = readincr(in);
  }
}

