#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int16>* __restrict in, output_stream<int32>* __restrict out) {
    const int32 window_size = 4;
    int32 sum = 0;
    int16 history[4] = {0, 0, 0, 0};
    int16 idx = 0;

    // Fill initial window
    for (int i = 0; i < window_size; i++) {
        int16 sample = readincr(in);
        history[i] = sample;
        sum += (int32)sample;
    }
    writeincr(out, sum / window_size);

    // Sliding window processing
    for (int i = 0; i < 60; i++) {
        int16 new_sample = readincr(in);
        int16 old_sample = history[idx];
        sum = sum - (int32)old_sample + (int32)new_sample;
        history[idx] = new_sample;
        idx = (idx + 1) % window_size;

        // Vector processing with concat of different element types
        aie::vector<int16, 8> v16 = aie::broadcast<int16, 8>(new_sample);
        aie::vector<int32, 4> v32 = aie::broadcast<int32, 4>(sum / window_size);
        auto combined = aie::concat(v16, v32);

        writeincr(out, sum / window_size);
    }
}

