#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

// 12-tap FIR filter with power-of-2 vector lanes
// Coefficients: symmetric low-pass, Q15 normalized
const int16 coeff[12] = {64, 128, 256, 512, 1024, 2048, 2048, 1024, 512, 256, 128, 64};

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
  // Delay line state - 12 samples history
  uint16 delay[12] = {0};

  // Process 64 samples per invocation
  const int samples = 64;

  for (int s = 0; s < samples; s++) {
    // Shift delay line: move older samples down
    for (int i = 11; i > 0; i--) {
      delay[i] = delay[i-1];
    }
    // Read new sample
    delay[0] = readincr(in);

    // Compute FIR sum using vectorized accumulation
    // Load 12 samples into vector - lane count must be power of 2
    aie::vector<int16, 12> vdelay = aie::load_v<12>(delay);
    aie::vector<int16, 12> vcoeff = aie::load_v<12>(coeff);

    // Multiply-accumulate
    aie::accum<acc48, 12> acc = aie::mul(vdelay, vcoeff);

    // Sum all lanes to get final result
    int64 sum = 0;
    for (int i = 0; i < 12; i++) {
      sum += acc.to_vector<int32>(0)[i];
    }

    // Scale: divide by 4096 (sum of coeffs) with rounding
    const int scale_shift = 12;
    int32 result = (int32)((sum + (1 << (scale_shift - 1))) >> scale_shift);

    // Saturate to uint16 range
    if (result < 0) result = 0;
    if (result > 65535) result = 65535;

    writeincr(out, (uint16)result);
  }
}

