void prefix_sum(input_stream<int16>* in, output_stream<int32>* out) {
  constexpr int samples = 64;

  int32_t acc = 0;

  for (int i = 0; i < samples; i += 8) {
    aie::vector<int16, 8> vin = readincr_v<8>(in);

    aie::vector<int16, 16> vin_wide = aie::concat(vin, vin);
    aie::vector<int16, 8> coeff = aie::broadcast<int16, 8>(1);

