    int16_t lane2 = vin[2];
    int16_t lane3 = vin[3];
    int16_t lane4 = vin[4];
    int16_t lane5 = vin[5];
    int16_t lane6 = vin[6];
    int16_t lane7 = vin[7];

    acc += lane0;
    writeincr(out, acc);
    acc += lane1;
    writeincr(out, acc);
    acc += lane2;
    writeincr(out, acc);
    acc += lane3;
    writeincr(out, acc);
    acc += lane4;
    writeincr(out, acc);
    acc += lane5;
    writeincr(out, acc);
    acc += lane6;
    writeincr(out, acc);
    acc += lane7;
    writeincr(out, acc);
  }
}

