void moving_avg(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 window_len = 8;
    const int16 shift_amt = 3;

    aie::vector<int16, 16> samples = aie::zeros<int16, 16>();
    aie::vector<int16, 8> coeffs = aie::broadcast<int16, 8>(1);

    aie::accum<acc48, 16> acc;

