        acc = aie::sliding_mul<8, 1>(coeffs, 0, samples, 0);

        int16 result = aie::srs(acc, shift_amt);
        writeincr(out, result);

        for (int i = 0; i < window_len - 1; i++) {
            samples[i] = samples[i + 1];
        }
    }
}

