#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void clip_threshold(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 threshold_pos = 10000;
    const int16 threshold_neg = -10000;
    const int samples = 64;

    for (int i = 0; i < samples / 16; i++) {
        aie::vector<int16, 16> vec = readincr_v<16>(in);
        aie::vector<int16, 16> result;

        aie::vector<int16, 8> upper = aie::extract<8>(vec, 1);
        aie::vector<int16, 8> lower = aie::extract<8>(vec, 0);

        for (int j = 0; j < 16; j++) {
            int16 val = vec[j];
            if (val > threshold_pos) {
                result[j] = threshold_pos;
            } else if (val < threshold_neg) {
                result[j] = threshold_neg;
            } else {
                result[j] = val;
            }
        }

        writeincr_v<16>(out, result);
    }
}

