void running_sum(input_stream<int16>* in, output_stream<int16>* out) {
  // Process 64 samples with vectorized load/store
  // Using power-of-2 lane count: 8 (valid), not 3 (invalid)
  constexpr int samples = 64;
  constexpr int lanes = 8;           // power of 2
  constexpr int unroll = samples / lanes;

  int16 buf[lanes];
