void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    const uint16_t taps[4] = {1, 2, 2, 1};
    uint16_t delay_line[4] = {0, 0, 0, 0};
    const uint16_t scale_shift = 2;
    const uint16_t num_samples = 64;

    for (uint16_t s = 0; s < num_samples; s++) {
        uint16_t sample = readincr(in);

        delay_line[3] = delay_line[2];
        delay_line[2] = delay_line[1];
        delay_line[1] = delay_line[0];
        delay_line[0] = sample;

        aie::accum<acc48, 4> acc = aie::zeros<acc48, 4>();
        aie::vector<uint16_t, 4> v_delay = aie::load_v<4>(delay_line);
        aie::vector<uint16_t, 4> v_taps = aie::load_v<4>(taps);
        acc = aie::mac(acc, v_delay, v_taps);

        uint16_t result = aie::srs(acc, scale_shift)[0];
        writeincr(out, result);
    }
}

