#define WINDOW_SIZE 4
#define NUM_ITERATIONS 64

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
    int32 state[WINDOW_SIZE] = {0, 0, 0, 0};
    int32 phase = 0;

    for (int n = 0; n < NUM_ITERATIONS; n++) {
        int32 sample = readincr(in);

        state[phase] = sample;

        aie::accum<acc48, 4> acc = aie::zeros<acc48, 4>();
        aie::vector<int32, 4> vec = aie::load_v<4>(state);
        acc = aie::mac(acc, vec, aie::broadcast<int32, 4>(1));

        int32 result = acc.to_vector<int32>(2)[0];

        writeincr(out, result);

        phase = (phase + 1) & (WINDOW_SIZE - 1);
    }
}

