        int16 sample = readincr(in);
        int16 result;

        int32 abs_val = sample;
        if (abs_val < 0) {
            abs_val = -abs_val;
        }

        if (abs_val > THRESHOLD) {
            if (sample > 0) {
                result = CLIP_HIGH;
            } else {
                result = CLIP_LOW;
            }
        } else {
            result = sample;
        }

        writeincr(out, result);
    }
}

