#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 coeffs[4] = {1, 2, 3, 4};
    int16 delay_line[4] = {0, 0, 0, 0};
    const int num_samples = 64;

    for (int n = 0; n < num_samples; n++) {
        int16 sample = readincr(in);

        for (int i = 3; i > 0; i--) {
            delay_line[i] = delay_line[i-1];
        }
        delay_line[0] = sample;

        aie::vector<int16, 4> coeff_vec = aie::load_v<4>(coeffs);
        aie::vector<int16, 4> delay_vec = aie::begin_vector<3>(delay_line)[0];

        aie::accum<acc48, 4> acc = aie::mul(coeff_vec, delay_vec);
        int16 result = aie::srs(acc, 8);
        writeincr(out, result);
    }
}

