void fir_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 coeffs[4] = {1, 2, 2, 1};
    const int scale = 2;
    int16 delay[4] = {0, 0, 0, 0};

    for (int n = 0; n < 64; n++) {
