// FILE: kernels/clip.cc
#include <aie_api/aie.hpp>

void clip_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t iterations = 8;
    const int32_t threshold = 100;
    const int32_t upper_limit = 127;
    const int32_t lower_limit = -128;

    for (int i = 0; i < iterations; ++i) {
        aie::vector<int32_t, 4> vec = readincr_v<4>(in);
        aie::vector<int32_t, 4> result;

        for (int j = 0; j < 4; ++j) {
            int32_t val = vec[j];
            int32_t out_val;

            if (val > threshold) {
                out_val = upper_limit;
            } else if (val < -threshold) {
                out_val = lower_limit;
            } else {
                out_val = val;
            }

            result[j] = out_val;
        }

        writeincr_v<4>(out, result);
    }
}

