void fir_filter(input_stream<int32>* in, output_stream<int32>* out) {
    const int16_t taps[8] = {1, 2, 3, 4, 3, 2, 1, 0};
    const int32_t shift = 0;
    const int32_t samples = 64;

    int16_t delay_line[8] = {0};

    for (int32_t s = 0; s < samples; s += 8) {
        aie::vector<int16, 8> sample_vec = readincr_v<8>(in);

        for (int32_t i = 0; i < 8; i++) {
            delay_line[i] = sample_vec[i];
        }

        aie::vector<int16, 8> tap_vec = aie::load_v<8>(taps);
        aie::accum<acc48, 8> acc = aie::sliding_mul_sym<8, 1, 1>(tap_vec, 0, delay_line, 0);

        aie::vector<int16, 8> result = acc.to_vector<int16>(shift);
        writeincr_v<8>(out, result);
    }
}

