        delay_line[3] = delay_line[2];
        delay_line[2] = delay_line[1];
        delay_line[1] = delay_line[0];
        delay_line[0] = sample;

        aie::vector<int32_t, 4> data_vec = aie::load_v<4>(delay_line);
        aie::accum<acc80, 4> prod = aie::mul(data_vec, tap_vec);
        int32_t result = aie::srs(prod, shift_bits);
        writeincr(out, result);
    }
}

