void fir_int32(input_stream<int32_t>* in, output_stream<int32_t>* out) {
  // 4-tap symmetric FIR: coeffs [1, 2, 2, 1], normalized by scale
  const int32_t c0 = 1;
  const int32_t c1 = 2;
  const int32_t c2 = 2;
  const int32_t c3 = 1;
  const int32_t scale_bits = 2;  // divide by 4

  int32_t x[4] = {0, 0, 0, 0};
  int32_t idx = 0;

  for (int n = 0; n < 64; n++) {
    int32_t sample = readincr(in);

    x[idx] = sample;

    int32_t tap0 = x[idx];
    int32_t tap1 = x[(idx + 1) & 3];
    int32_t tap2 = x[(idx + 2) & 3];
    int32_t tap3 = x[(idx + 3) & 3];

    int64_t acc = (int64_t)c0 * tap0 + (int64_t)c1 * tap1
                + (int64_t)c2 * tap2 + (int64_t)c3 * tap3;

    int32_t result = (int32_t)(acc >> scale_bits);

    writeincr(out, result);

    idx = (idx + 1) & 3;
  }
}

}

