void fir_kernel(input_stream<uint16>* in, output_stream<uint16>* out) {
    const int16 coeff[4] = {1, 2, 3, 4};
    const int samples = 64;
    const int taps = 4;

    uint16 delay_line[taps] = {0};
    int write_idx = 0;

