#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

static constexpr int16_t COEFF[4] = {1, 2, 2, 1};
static constexpr int SHIFT = 2;
static constexpr int NSAMPLES = 64;

void fir_filter(input_stream<int16_t>* in, output_stream<int16_t>* out) {
    int16_t delay[4] = {};

    for (int n = 0; n < NSAMPLES; n++) {
        int32_t acc = 0;

        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];
        delay[0] = readincr(in);

        acc += delay[0] * COEFF[0];
        acc += delay[1] * COEFF[1];
        acc += delay[2] * COEFF[2];
        acc += delay[3] * COEFF[3];

        int16_t result = (int16_t)(acc >> SHIFT);
        writeincr(out, result);
    }
}

