void fir_filter(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t taps[4] = {1, 2, 2, 1};
    const int32_t scale = 6;
    int32_t shift_reg[4] = {0, 0, 0, 0};

