#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 taps[4] = {1, 2, 2, 1};
    int16 delay[4] = {0, 0, 0, 0};
    const int num_samples = 64;
    const int num_taps = 4;

    for (int s = 0; s < num_samples; s++) {
        int32 sum = 0;
        int16 sample = readincr(in);

        // Shift delay line
        for (int i = num_taps - 1; i > 0; i--) {
            delay[i] = delay[i-1];
        }
        delay[0] = sample;

        // Compute FIR output
        for (int i = 0; i < num_taps; i++) {
            sum += (int32)delay[i] * (int32)taps[i];
        }

        // Scale down by 2 (normalize for unity gain)
        int16 out_sample = (int16)(sum >> 2);
        writeincr(out, out_sample);
    }
}

