#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_average(input_stream<int16_t>* in, output_stream<int16_t>* out) {
  // 4-tap moving average filter
  const int16_t TAP_COUNT = 4;
  int32_t sum = 0;

  // Initialize delay line with first samples
  int16_t delay_line[4] = {0, 0, 0, 0};
  int16_t write_idx = 0;

  // Process 64 samples
  const int16_t NUM_SAMPLES = 64;

  for (int16_t n = 0; n < NUM_SAMPLES; n++) {
    int16_t sample = readincr(in);

    // Update delay line
    int16_t oldest = delay_line[write_idx];
    delay_line[write_idx] = sample;

    // Update running sum: add new sample, subtract oldest
    sum = sum + sample - oldest;

    // Advance write index with modulo
    write_idx = write_idx + 1;
    if (write_idx >= TAP_COUNT) {
      write_idx = 0;
    }

    // Output average (sum / 4)
    int16_t output = (int16_t)(sum >> 2);
    writeincr(out, output);
  }
}

