void fir_kernel(input_stream<uint16_t>* in, output_stream<uint16_t>* out) {
    // 4-tap FIR coefficients (scaled to preserve precision)
    const uint16_t coeff[4] = {1, 2, 2, 1};
    const uint16_t scale_shift = 2;  // divide by 4

    // Delay line state
    uint16_t delay[4] = {0, 0, 0, 0};

