        acc += coeff[0] * delay[0];
        acc += coeff[1] * delay[1];
        acc += coeff[2] * delay[2];
        acc += coeff[3] * delay[3];

        // Scale and output
        uint16_t result = (uint16_t)(acc >> scale_shift);
        writeincr(out, result);
    }
}

