void fir_stream_kernel(input_stream<int32>* in, output_stream<int32>* out) {
    const int32_t taps[4] = {1, -3, 3, -1};
    const int num_taps = 4;
    const int samples = 64;

    int32_t delay_line[4] = {0, 0, 0, 0};

    for (int s = 0; s < samples; s++) {
        int32_t sample = readincr(in);

        delay_line[3] = delay_line[2];
        delay_line[2] = delay_line[1];
        delay_line[1] = delay_line[0];
        delay_line[0] = sample;

        int64_t acc = 0;
        for (int t = 0; t < num_taps; t++) {
            acc += (int64_t)delay_line[t] * (int64_t)taps[t];
        }

        int32_t result = (int32_t)(acc >> 14);
        writeincr(out, result);
    }
}

