constexpr unsigned WINDOW_SIZE = 4;
constexpr unsigned ITERATIONS = 128;

void moving_avg(const input_stream<int32>* restrict in, output_stream<int32>* restrict out) {
    int32_t delay_line[WINDOW_SIZE] = {0};
    int32_t sum = 0;
    unsigned write_idx = 0;

    for (unsigned n = 0; n < ITERATIONS + WINDOW_SIZE - 1; n++) {
        int32_t new_sample = 0;
