        sum = sum - oldest + new_sample;
        delay_line[write_idx] = new_sample;
        write_idx = (write_idx + 1) % WINDOW_SIZE;

        if (n >= WINDOW_SIZE - 1) {
            int32_t avg = sum / (int32_t)WINDOW_SIZE;
            writeincr(out, avg);
        }
    }
}

