void moving_avg_kernel(input_buffer<int32_t>& in, output_buffer<int32_t>& out) {
    // 4-tap moving average filter
    const int32_t WINDOW_SIZE = 4;
    const int32_t ITERATIONS  = 64;

    int32_t delay_line[4] = {0, 0, 0, 0};
    int32_t tap_idx = 0;

    auto in_iter = aie::begin(in);
    auto out_iter = aie::begin(out);

    for (int i = 0; i < ITERATIONS; i++) {
        int32_t sample = *in_iter++;

        // Update delay line at current tap position
        delay_line[tap_idx] = sample;

        // Compute sum of delay line
        int64_t sum = 0;
        for (int j = 0; j < WINDOW_SIZE; j++) {
            sum += delay_line[j];
        }

        // Scale: divide by WINDOW_SIZE (power of 2, shift by 2)
        int32_t output = (int32_t)(sum >> 2);

        *out_iter++ = output;

        // Advance circular buffer index
        tap_idx = (tap_idx + 1) % WINDOW_SIZE;
    }
}

