void moving_avg(input_buffer<int32_t>& in, output_buffer<int32_t>& out) {
    const int32_t TAPS = 4;
    int32_t delay_line[TAPS] = {0, 0, 0, 0};
    int32_t phase = 0;

    // Process 128 samples (512 bytes expected from window size)
    for (int32_t n = 0; n < 128; n++) {
        int32_t sample = in.data()[n];

        int32_t oldest = delay_line[phase];
        delay_line[phase] = sample;

        int32_t sum = oldest + delay_line[(phase + 1) % TAPS] + 
                      delay_line[(phase + 2) % TAPS] + delay_line[(phase + 3) % TAPS];
        int32_t result = sum / TAPS;

        out.data()[n] = result;

        phase = (phase + 1) % TAPS;
    }
}

