#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int16>* in, output_stream<int16>* out) {
  const int16 TAP_COUNT = 4;
  int16 delay_line[TAP_COUNT] = {0};
  int16 write_idx = 0;

  for (int n = 0; n < 128; n++) {
    int16 sample = readincr(in);
    delay_line[write_idx] = sample;

    int32 sum = 0;
    for (int t = 0; t < TAP_COUNT; t++) {
      int16 idx = (write_idx + TAP_COUNT - t) & (TAP_COUNT - 1);
      sum += delay_line[idx];
    }

    int16 avg = (int16)(sum >> 2);
    writeincr(out, avg);

    write_idx = (write_idx + 1) & (TAP_COUNT - 1);
  }
}

