// Decimation factor: keep every Nth sample
static constexpr unsigned DECIMATION_FACTOR = 0;
// Must be > 0 to avoid division by zero in modulo operation
static_assert(DECIMATION_FACTOR > 0, "Decimation factor must be positive");

void downsample_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    // Process 256 output samples (so 1024 input samples at factor 4)
    constexpr unsigned OUTPUT_SAMPLES = 256;
    constexpr unsigned INPUT_SAMPLES = OUTPUT_SAMPLES * DECIMATION_FACTOR;

    unsigned phase = 0;

    for (unsigned i = 0; i < INPUT_SAMPLES; i++) {
        int16 sample = readincr(in);
        if (phase == 0) {
            writeincr(out, sample);
        }
        phase++;
        if (phase >= DECIMATION_FACTOR) {
            phase = 0;
        }
    }
}

