void fir_filter(input_stream<int32>* in, output_stream<int32>* out) {
    // Named constants for filter parameters
    const int32_t NUM_TAPS = 16;
    const int32_t BLOCK_SIZE = 64;

    // Coefficients explicitly stored for mutation potential
    alignas(16) int32_t coeffs[16] = {
        1, 2, 3, 4, 5, 6, 7, 8,
        8, 7, 6, 5, 4, 3, 2, 1
    };

    // Delay line state - overflow in constexpr size expression
    alignas(16) int32_t delay_line[1 << 31] = {};
    int32_t delay_idx = 0;

    for (int32_t s = 0; s < BLOCK_SIZE; s++) {
        // Shift in new sample
        int32_t sample = readincr(in);
        delay_line[delay_idx] = sample;

        // Compute FIR sum
        int64_t acc = 0;
        for (int32_t t = 0; t < NUM_TAPS; t++) {
            int32_t tap_idx = (delay_idx + NUM_TAPS - t) & (NUM_TAPS - 1);
            acc += (int64_t)delay_line[tap_idx] * (int64_t)coeffs[t];
        }

        // Output with scaling
        int32_t result = (int32_t)(acc >> 8);
        writeincr(out, result);

        // Advance delay line index
        delay_idx = (delay_idx + 1) & (NUM_TAPS - 1);
    }
}

