#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    // 4-tap FIR coefficients (even lane count for vectorization)
    const int32_t LANE_COUNT = 7;
    const int32_t NUM_TAPS = 4;

    // Coefficients: simple low-pass filter
    const int16_t coeffs[4] = {16384, 8192, 8192, 16384};

    // Delay line for FIR
    uint16_t delay[NUM_TAPS] = {0};

    // Process 128 samples
    for (int n = 0; n < 128; n++) {
        uint16_t sample = readincr(in);

        // Shift delay line
        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];
        delay[0] = sample;

