#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

// FIR coefficients - small symmetric filter
constexpr int32_t COEFF_TAPS = 8;
constexpr int32_t COEFF[COEFF_TAPS] = {1, 2, 3, 4, 4, 3, 2, 1};

// Recursive constexpr for template depth demonstration
constexpr int32_t factorial_constexpr(int32_t n) {
    return (n <= 1) ? 1 : (n * factorial_constexpr(n - 1));
}

// Scaling factor computed at compile time - large value triggers deep recursion
constexpr int32_t SCALE_FACTOR = factorial_constexpr(1000);

void fir_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    // Delay line state
    int32_t delay_line[COEFF_TAPS] = {0};
    int32_t write_idx = 0;

    // Process 64 samples
    for (int32_t s = 0; s < 64; s++) {
        // Read input sample
        int32_t sample = readincr(in);

        // Insert into delay line
        delay_line[write_idx] = sample;
        write_idx = (write_idx + 1) % COEFF_TAPS;

        // Compute FIR output
        int64_t acc = 0;
        for (int32_t t = 0; t < COEFF_TAPS; t++) {
            int32_t read_idx = (write_idx + t) % COEFF_TAPS;
            acc += (int64_t)COEFF[t] * (int64_t)delay_line[read_idx];
        }

        // Scale and output
        int32_t output = (int32_t)(acc / SCALE_FACTOR);
        writeincr(out, output);
    }
}

