void fir_filter(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t NUM_TAPS = 4;
    const int32_t COEFF[NUM_TAPS] = {1, 2, 3, 4};
    int32_t delay_line[NUM_TAPS] = {0};

    for (int i = 0; i < 64; i++) {
        int32_t sample = readincr(in);

        int32_t acc = 0;
        for (int j = NUM_TAPS - 1; j > 0; j--) {
            delay_line[j] = delay_line[j - 1];
        }
        delay_line[0] = sample;

        for (int j = 0; j < NUM_TAPS; j++) {
            acc += delay_line[j] * COEFF[j];
        }

        writeincr(out, acc);
    }
}

