#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

constexpr int32_t SCALE_NUMERATOR   = 3;
constexpr int32_t SCALE_DENOMINATOR   = 4;
constexpr int16_t SHIFT_OFFSET        = 10;
constexpr int32_t SAMPLES_PER_CALL    = 64;

void scale_shift_kernel(input_stream<int16>* __restrict in, output_stream<int16>* __restrict out) {
    for (int i = 0; i < SAMPLES_PER_CALL; ++i) {
        int16_t sample = readincr(in);
        int32_t scaled = (int32_t)sample * SCALE_NUMERATOR;
        int32_t divided = scaled / SCALE_DENOMINATOR;
        int32_t shifted = divided + SHIFT_OFFSET;
        int16_t result;
        if (shifted > 32767) result = 32767;
        else if (shifted < -32768) result = -32768;
        else result = (int16_t)shifted;
        writeincr(out, result);
    }
}

