void moving_avg(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 window_size = 4;
    const int16 shift = 2;

    int32 acc = 0;
    int16 history[4] = {0, 0, 0, 0};
    int16 idx = 0;

    for (int i = 0; i < 64; i++) {
        int16 sample = readincr(in);

        acc -= history[idx];
        history[idx] = sample;
        acc += sample;

        int16 avg = (int16)(acc >> shift);
        writeincr(out, avg);

        idx++;
        if (idx >= window_size) idx = 0;
    }
}

