void scale_shift_kernel(input_stream<uint16>* in, output_stream<uint16>* out) {
  const uint16 scale_num = 3;
  const uint16 scale_denom = 2;
  const uint16 shift_val = 128;
  const uint16 max_val = 4095;

  for (uint16 i = 0; i < 64; i++) {
