#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int32_t>* in, output_stream<int32_t>* out) {
  const int32_t taps[4] = {1, 2, 3, 4};
  const int32_t num_taps = 4;
  const int32_t num_samples = 64;

  int32_t delay_line[4] = {0, 0, 0, 0};

  for (int32_t n = 0; n < num_samples; n++) {
    int32_t sample = readincr(in);

    // Shift delay line
    for (int32_t i = num_taps - 1; i > 0; i--) {
      delay_line[i] = delay_line[i - 1];
    }
    delay_line[0] = sample;

    // Compute FIR output
    int64_t acc = 0;
    for (int32_t i = 0; i < num_taps; i++) {
      acc += (int64_t)taps[i] * (int64_t)delay_line[i];
    }
    int32_t result = (int32_t)(acc >> 8);

    writeincr(out, result);
  }
}

