void clip_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t THRESHOLD_LOW = -1000;
    const int32_t THRESHOLD_HIGH = 1000;
    const int32_t ITERATIONS = 64;

    for (int i = 0; i < ITERATIONS; i++) {
        int32_t sample = readincr(in);
