        aie::vector<int32_t, 16> vout;
        for (int j = 0; j < 16; j++) {
            int32_t s = vin[j];
            if (s < THRESHOLD_LOW) {
                vout[j] = THRESHOLD_LOW;
            } else if (s > THRESHOLD_HIGH) {
                vout[j] = THRESHOLD_HIGH;
            } else {
                vout[j] = s;
            }
        }
        writeincr_v<16>(out, vout);
    }
}

