void moving_avg(input_stream<int16>* in, output_buffer<int32>& out) {
    const int16 window_size = 4;
    const int16 num_outputs = 256;

    int32 accum = 0;
    int16 delay_line[4] = {0, 0, 0, 0};
    int16 write_idx = 0;

    for (int i = 0; i < window_size - 1; i++) {
        int16 sample = readincr(in);
        accum += sample;
        delay_line[write_idx] = sample;
        write_idx = (write_idx + 1) % window_size;
    }

    auto out_iter = aie::begin(out);
    for (int i = 0; i < num_outputs; i++) {
        int16 sample = readincr(in);
        accum += sample;
        delay_line[write_idx] = sample;

        int32 avg = accum / window_size;
        *out_iter++ = avg;

        int16 oldest = delay_line[write_idx];
        accum -= oldest;
        write_idx = (write_idx + 1) % window_size;
    }
}

