void threshold_clip(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 threshold = 1000;
    const int16 clip_max = 32767;
    const int16 clip_min = -32767;
    const int samples_per_block = 64;

    int16 local_buf[samples_per_block];

    for (int i = 0; i < samples_per_block; i++) {
        int16 val = readincr(in);
        local_buf[i] = val;
    }

    for (int i = 0; i < samples_per_block; i++) {
        int16 val = local_buf[i];
        int16 result;

        if (val > threshold) {
            result = clip_max;
        } else if (val < -threshold) {
            result = clip_min;
        } else {
            result = val;
        }

        local_buf[i] = result;
    }

    aie::vector<int16, 16> vec;
    for (int i = 0; i < samples_per_block; i += 16) {
        vec = aie::load_v<16>(&local_buf[i]);
        aie::store_v<16>(&local_buf[i], vec);
    }

    for (int i = 0; i < samples_per_block; i++) {
        writeincr(out, local_buf[i]);
    }
}

