#include <aie_api/aie_adf.hpp>

// 4-tap symmetric FIR: coefficients sum to unity for DC preservation
static const int32_t COEFF_A = 1;   // center tap (multiplied by 2 in symmetric)
static const int32_t COEFF_B = 2;   // outer tap
static const int32_t SHIFT = 2;     // divide by 4 for normalization

void fir_int32_stream(input_stream<int32>* __restrict in,
                      output_stream<int32>* __restrict out) {
    // Delay line state - explicitly named for mutation
    int32_t d0 = 0;  // oldest sample
    int32_t d1 = 0;  // middle sample
    int32_t d2 = 0;  // newest sample before current

    const int32_t NUM_SAMPLES = 64;

    // Vectorized processing with aie::vector
    aie::vector<double, 8> vec_coeff_a = aie::broadcast<double, 8>((double)COEFF_A);
    aie::vector<double, 8> vec_coeff_b = aie::broadcast<double, 8>((double)COEFF_B);

    for (int32_t n = 0; n < NUM_SAMPLES; n++) {
        int32_t x = readincr(in);

        // Symmetric FIR: y = COEFF_B*(d0 + x) + COEFF_A*d1
        int32_t outer_sum = d0 + x;
        int32_t center = d1;

        // Use int64 for intermediate to avoid overflow
        int64_t acc = (int64_t)COEFF_B * outer_sum + (int64_t)COEFF_A * center;

        // Normalize with shift
        int32_t y = (int32_t)(acc >> SHIFT);

        writeincr(out, y);

        // Update delay line
        d0 = d1;
        d1 = d2;
        d2 = x;
    }
}

