// Valid accumulator tags: acc48, acc80, cacc48 (complex only)
// For real int16 data, use acc48 or acc80

void scale_shift_kernel(input_stream<int16>* in, output_stream<int16>* out) {
  const int16 scale_val = 3;
  const int16 shift_val = 16;
  const int32 lanes = 16;

  // Use cacc80 for real int16 accumulation (complex accumulator with real data)
  aie::accum<cacc80, lanes> acc = aie::zeros<cacc80, lanes>();

  for (int i = 0; i < 32; i++) {
    aie::vector<int16, lanes> vin = readincr_v<lanes>(in);

    // Scale and accumulate
    aie::vector<int16, lanes> scale_vec = aie::broadcast<int16, lanes>(scale_val);
    acc = aie::mac(acc, vin, scale_vec);

    // Convert to vector with right-shift
    aie::vector<int16, lanes> vscaled = acc.to_vector<int16>(shift_val);

    // Add offset shift
    aie::vector<int16, lanes> shift_vec = aie::broadcast<int16, lanes>(shift_val);
    aie::vector<int16, lanes> vout = vscaled + shift_vec;

    writeincr_v<lanes>(out, vout);

    // Reset accumulator for next iteration
    acc = aie::zeros<cacc80, lanes>();
  }
}

