void moving_avg_kernel(input_stream<int16>* in, output_stream<int16>* out) {
  const unsigned TAP_SIZE = 4;
  const unsigned NUM_ITER = 64;

  aie::vector<int16, 8> delay_line = aie::zeros<int16, 8>();

  for (unsigned i = 0; i < NUM_ITER; i++) {
    int16 sample = readincr(in);

    // Shift delay line and insert new sample
    delay_line = aie::shuffle_down(delay_line, 1);
    delay_line[0] = sample;

