#include <aie_api/aie_adf.hpp>

void prefix_scan(input_stream<int16>* in, output_stream<int16>* out) {
    const int samples = 64;
    int32 running_sum = 0;

    aie::vector<int16, 8> vec_low = aie::zeros<int16, 8>();
    aie::vector<int32, 8> vec_high = aie::zeros<int32, 8>();

    for (int i = 0; i < samples / 8; i++) {
        aie::vector<int16, 8> vin = readincr_v<8>(in);

        for (int j = 0; j < 8; j++) {
            running_sum += vin[j];
            vec_low[j] = (int16)running_sum;
        }

        auto result = aie::interleave_unzip(vec_low, vec_high);
        writeincr_v<8>(out, result);
    }
}

