#include <aie_api/aie_adf.hpp>

void fir_shuffle_kernel(input_stream<int16_t>* in, output_stream<int16_t>* out) {
    // 4-tap FIR with coefficients [1, 2, 2, 1] for DC gain of 6
    const int16_t c0 = 1;
    const int16_t c1 = 2;
    const int16_t c2 = 2;
    const int16_t c3 = 1;
    const int32_t shift_val = 2;  // divide by 4 (right shift)

    // Delay line state
    int16_t d0 = 0, d1 = 0, d2 = 0, d3 = 0;

    for (int i = 0; i < 64; i++) chess_prepare_for_pipelining {
        int16_t x = readincr(in);

        // Shift delay line
        d3 = d2;
        d2 = d1;
        d1 = d0;
        d0 = x;

        // MAC operation with explicit coefficient naming
        int32_t acc = (int32_t)c0 * d0;
        acc += (int32_t)c1 * d1;
        acc += (int32_t)c2 * d2;
        acc += (int32_t)c3 * d3;

        // Apply shift for normalization
        int16_t y = (int16_t)(acc >> shift_val);

        // Use shuffle_up to rotate delay line values for next iteration
        aie::vector<int16_t, 4> delay_vec = aie::vector<int16_t, 4>(d0, d1, d2, d3);
        // Negative shift amount in template expression causes compile error
        delay_vec = aie::shuffle_up<-1>(delay_vec);

        writeincr(out, y);
    }
}

