void fir_filter(input_stream<uint16>* in, output_stream<uint32>* out) {
    const uint16_t coeffs[TAP_COUNT] = {1, 2, 3, 4, 5, 4, 3, 2};

    aie::vector<uint16, VECTOR_SIZE> coeff_vec = aie::load_v<VECTOR_SIZE>(coeffs);

