            acc = aie::mac(acc, samples, aie::broadcast<uint16, VECTOR_SIZE>(coeff[0]));
        }

        aie::vector<uint32, VECTOR_SIZE> result = acc.to_vector<uint32>(0);
        writeincr_v<VECTOR_SIZE>(out, result);
    }
}

