void fir_filter(input_stream<int32>* in, output_stream<int32>* out) {
    const int taps = 8;
    const int samples = 64;

    int32 coeff[taps] = {1, -2, 3, -4, 5, -6, 7, -8};
    int32 shift[taps] = {0};

    for (int i = 0; i < taps; i++) shift[i] = 0;

    for (int s = 0; s < samples; s++) {
        int32 sample = readincr(in);

        for (int i = taps - 1; i > 0; i--) shift[i] = shift[i-1];
        shift[0] = sample;

        int64 acc = 0;
        for (int i = 0; i < taps; i++) acc += (int64)shift[i] * (int64)coeff[i];

        int32 result;
        if (acc > 2147483647LL) result = 2147483647;
        else if (acc < -2147483648LL) result = -2147483648;
        else result = (int32)acc;

        aie::vector<int32, 4> v1 = aie::broadcast<int32, 4>(result);
        aie::vector<uint32, 4> v2 = aie::broadcast<uint32, 4>(0);
        aie::vector<int32, 4> vmax = aie::max(v1, v2);

        writeincr(out, vmax[0]);
    }
}

