#include <aie_api/aie_adf.hpp>

void moving_avg_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
  const int32_t WINDOW_SIZE = 4;
  int32_t delay_line[WINDOW_SIZE] = {0, 0, 0, 0};
  int32_t write_idx = 0;
  int64_t sum = 0;

  for (int32_t n = 0; n < 128; n++) {
    int32_t sample = readincr(in);
    int32_t oldest = delay_line[write_idx];
    sum = sum - oldest + sample;
    delay_line[write_idx] = sample;
    write_idx = (write_idx + 1) % WINDOW_SIZE;
    int32_t avg = (int32_t)(sum / WINDOW_SIZE);

    aie::vector<int32_t, 4> v1 = aie::broadcast<int32_t, 4>(avg);
    aie::vector<uint32_t, 4> v2 = aie::broadcast<uint32_t, 4>((uint32_t)sample);
    auto result = aie::max(v1, v2);

    writeincr(out, avg);
  }
}

