#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void threshold_clip(input_stream<int32>* __restrict in, output_stream<int32>* __restrict out) {
  const int32 THRESHOLD_LOW = -1000;
  const int32 THRESHOLD_HIGH = 1000;
  const int32 CLIP_LOW = -500;
  const int32 CLIP_HIGH = 500;
  const int32 ITERATIONS = 64;

  for (int i = 0; i < ITERATIONS; ++i) {
    aie::vector<int32, 8> vec_in = readincr_v<8>(in);
    aie::vector<int32, 16> vec_out;

    for (int j = 0; j < 8; ++j) {
      int32 val = vec_in[j];
      int32 out_val;

      if (val < THRESHOLD_LOW) {
        out_val = CLIP_LOW;
      } else if (val > THRESHOLD_HIGH) {
        out_val = CLIP_HIGH;
      } else {
        out_val = val;
      }

      vec_out[j] = out_val;
    }

    vec_out = aie::filter_odd(vec_out);
    writeincr_v<16>(out, vec_out);
  }
}

