#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void running_sum(input_stream<int16>* __restrict__ in,
                 output_stream<int16>* __restrict__ out) {
    const int samples = 128;
    const int lanes = 16;

    // int32 accumulator to avoid overflow during accumulation
    int32 accum = 0;

    for (int i = 0; i < samples / lanes; i++) {
        // Read vector of int16 samples
        aie::vector<int16, lanes> vec = readincr_v<lanes>(in);

        // Process each lane: running sum
        aie::vector<int16, lanes> out_vec;
        for (int j = 0; j < lanes; j++) {
            accum += vec[j];
            // Saturate to int16 range
            int16 sat_val = (int16)((accum > 32767) ? 32767 : 
                                    ((accum < -32768) ? -32768 : accum));
            out_vec[j] = sat_val;
        }

        // Write vector output
        writeincr_v<lanes>(out, sat_val);
    }
}

