#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    // 4-tap FIR with int16 coefficients
    const int16 coeffs[4] = {1, 2, 3, 4};
    const int16 sample_count = 64;

    // Delay line state - explicitly named for future mutation
    int16 delay[4] = {0, 0, 0, 0};

    for (int16 s = 0; s < sample_count; s++) {
        // Shift delay line
        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];

        // Read new sample - vector read with int32 element type mismatches int16 stream
        aie::vector<int32, 4> vin = readincr_v<4>(in);
        delay[0] = (int16)vin[0];

        // Compute FIR output using scalar int32 accumulator
        int32 acc = 0;
        for (int16 t = 0; t < 4; t++) {
            acc += (int32)delay[t] * (int32)coeffs[t];
        }

        // Scale and saturate to int16
        int16 result = (int16)(acc >> 4);
        writeincr(out, result);
    }
}

