void clip_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 threshold_pos = 1000;
    const int16 threshold_neg = -1000;
    const int samples = 64;

    for (int i = 0; i < samples / 8; i++) {
        aie::vector<int32, 8> vec = readincr_v<8>(in);

