#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int TAPS = 4;
    const int LANES = 4;

    int32_t coeffs[TAPS] = {1, 2, 3, 4};
    int32_t delay[TAPS] = {0};

    for (int n = 0; n < 64; n++) {
        aie::vector<int32_t, 8> vin = readincr_v<LANES>(in);

        for (int l = 0; l < LANES; l++) {
            int32_t sample = vin[l];

            for (int i = TAPS - 1; i > 0; i--) {
                delay[i] = delay[i - 1];
            }
            delay[0] = sample;

            int64_t acc = 0;
            for (int i = 0; i < TAPS; i++) {
                acc += (int64_t)coeffs[i] * delay[i];
            }

            int32_t result = (int32_t)(acc >> 8);
            writeincr(out, result);
        }
    }
}

