void threshold_clip(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 lower_bound = -1000;
    const int16 upper_bound = 1000;
    const int32 num_samples = 64;

    for (int32 i = 0; i < num_samples; i++) {
