void moving_avg(input_stream<int16>* in, output_stream<int16>* out) {
    constexpr int16 TAP_COUNT = 4;
    int16 delay_line[TAP_COUNT] = {0, 0, 0, 0};
    int16 write_idx = 0;

    const int16 SAMPLE_COUNT = 64;

    for (int16 n = 0; n < SAMPLE_COUNT; n++) {
        int16 sample = readincr(in);

        delay_line[write_idx] = sample;

        int32 acc = 0;
        for (int16 i = 0; i < TAP_COUNT; i++) {
