void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    // 4-tap FIR coefficients: [1, 2, 3, 4] scaled by 8 for fixed-point
    const int16 coeff[4] = {8, 16, 24, 32};
    const int shift = 3;
    const int samples = 64;

    int16 delay[4] = {0, 0, 0, 0};

