void moving_average_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t window_size = 4;
    int32_t buffer[4] = {0, 0, 0, 0};
    int32_t sum = 0;
    int32_t idx = 0;

    for (int32_t n = 0; n < 128; n += 4) {
        aie::vector<int32_t, 4> samples = readincr_v<4>(in);
        for (int32_t i = 0; i < 4; i++) {
            int32_t sample = samples[i];
            sum -= buffer[idx];
            buffer[idx] = sample;
            sum += sample;
            idx = (idx + 1) & (window_size - 1);
        }
        int32_t avg = sum >> 2;
        aie::vector<int32_t, 4> out_vec = aie::broadcast<int32_t, 4>(avg);
        writeincr_v<4>(out, out_vec);
    }
