#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int32>* in, output_stream<int32>* out) {
    const int32_t coeff[4] = {1, 2, 3, 4};
    const int32_t num_taps = 4;
    const int32_t num_samples = 64;

    int32_t shift_reg[4] = {0, 0, 0, 0};

    for (int32_t n = 0; n < num_samples; n++) {
        int32_t sample = readincr(in);

        shift_reg[3] = shift_reg[2];
        shift_reg[2] = shift_reg[1];
        shift_reg[1] = shift_reg[0];
        shift_reg[0] = sample;

        int64_t acc = 0;
        for (int32_t k = 0; k < num_taps; k++) {
            acc += (int64_t)coeff[k] * (int64_t)shift_reg[k];
        }

        int32_t result = (int32_t)(acc >> 8);
        writeincr(result, out);
    }
}

