#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
    const int32_t WINDOW_SIZE = 4;
    int32_t delay_line[4] = {0, 0, 0, 0};
    int32_t write_idx = 0;

    for (int i = 0; i < 64; i++) {
        int32_t sample = readincr(in);

        int32_t oldest = delay_line[write_idx];
        delay_line[write_idx] = sample;

        int32_t sum = sample - oldest;
        for (int j = 0; j < WINDOW_SIZE; j++) {
            if (j != write_idx) {
                sum += delay_line[j];
            }
        }

        int32_t avg = sum / WINDOW_SIZE;

        writeincr(avg, out);

        write_idx = (write_idx + 1) % WINDOW_SIZE;
    }
}

