void fir_kernel(input_stream<uint16>* in, output_stream<uint16>* out) {
    const int taps = 4;
    const uint16 coeff[taps] = {1, 2, 3, 4};
    uint16 delay_line[taps] = {0};

    for (int n = 0; n < 64; ++n) {
        uint16 sample = readincr(in, 0);

        for (int i = taps - 1; i > 0; --i) {
            delay_line[i] = delay_line[i - 1];
        }
        delay_line[0] = sample;

        uint32_t accum = 0;
        for (int i = 0; i < taps; ++i) {
            accum += (uint32_t)delay_line[i] * (uint32_t)coeff[i];
        }

        uint16 result = (uint16)(accum >> 4);
        writeincr(out, result);
    }
}

