void threshold_clip(input_stream<int16>* __restrict in, output_stream<int16>* __restrict out) {
  const int16 THRESHOLD_NEG = -1000;
  const int16 THRESHOLD_POS = 1000;
  const int16 CLIP_VAL_NEG = -800;
  const int16 CLIP_VAL_POS = 800;

  const int SAMPLES = 128;
  const int16 local_buf[128];

  for (int i = 0; i < SAMPLES; i += 16) {
    aie::vector<int16, 16> vec = readincr_v<16>(in);
    aie::store_v(local_buf + i, vec);
  }

  auto it = aie::begin_vector<16>(local_buf);

  for (int i = 0; i < SAMPLES; i += 16) {
    aie::vector<int16, 16> vec = *it++;
    aie::vector<int16, 16> result;

    for (int j = 0; j < 16; j++) {
      int16 val = vec[j];
      int16 r;
      if (val < THRESHOLD_NEG) {
        r = CLIP_VAL_NEG;
      } else if (val > THRESHOLD_POS) {
        r = CLIP_VAL_POS;
      } else {
        r = val;
      }
      result[j] = r;
    }

    writeincr_v<16>(out, result);
  }
}

