void fir_filter(input_buffer<int32_t>& in, output_buffer<int32_t>& out) {
    const int32_t coeffs[4] = {1, 2, 3, 4};
    int32_t delay_line[4] = {0, 0, 0, 0};
    const unsigned samples_per_frame = 64;
    const unsigned tap_count = 4;

    int32_t* in_ptr = (int32_t*)in.data();
    int32_t* out_ptr = (int32_t*)out.data();

    for (unsigned s = 0; s < samples_per_frame; s += 4) {
        chess_prepare_for_pipelining

        auto vin = aie::begin_vector<4>(in_ptr);
        aie::vector<int32_t, 4> sample_vec = *vin;

        for (unsigned v = 0; v < 4; v++) {
            int32_t sample = sample_vec[v];

            for (unsigned i = tap_count - 1; i > 0; i--) {
                delay_line[i] = delay_line[i - 1];
            }
            delay_line[0] = sample;

            int64_t acc = 0;
            for (unsigned t = 0; t < tap_count; t++) {
                acc += (int64_t)coeffs[t] * (int64_t)delay_line[t];
            }

            const unsigned scale_shift = 2;
            int32_t result = (int32_t)(acc >> scale_shift);
            out_ptr[s + v] = result;
        }

        in_ptr += 4;
    }
}

