#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_buffer<int32_t>& in, output_buffer<int32_t>& out) {
    const int32_t coeffs[4] = {1, 2, 3, 4};
    int32_t delay_line[4] = {0, 0, 0, 0};
    const int32_t num_samples = 64;

    auto in_iter = aie::begin(in);
    auto out_iter = aie::begin(out);

    for (int s = 0; s < num_samples; s++) {
        const int32_t sample = *in_iter++;

        // Shift delay line
        for (int i = 3; i > 0; i--) {
            delay_line[i] = delay_line[i-1];
        }
        delay_line[0] = sample;

        // MAC computation
        int64_t accum = 0;
        for (int t = 0; t < 4; t++) {
            accum += (int64_t)delay_line[t] * (int64_t)coeffs[t];
        }

        // Scale by 8 (sum of coeffs) with rounding
        const int32_t result = (int32_t)((accum + 4) >> 3);
        *out_iter++ = result;
    }
}

