#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg_kernel(input_stream<int32>* in, output_buffer<int32>& out) {
  const int32_t WINDOW_SIZE = 4;
  const int32_t OUTPUT_SAMPLES = 64;

  int32_t delay_line[4] = {0, 0, 0, 0};
  int32_t write_idx = 0;

  auto out_iter = aie::begin_vector<4>(out);

  for (int32_t n = 0; n < OUTPUT_SAMPLES; n += 4) {
    aie::vector<int32, 4> vec = aie::load_v<4>(out_iter);

    for (int32_t lane = 0; lane < 4; lane++) {
      int32_t sample = readincr(in);

      int32_t old_sample = delay_line[write_idx];
      delay_line[write_idx] = sample;

      int32_t sum = sample - old_sample;
      for (int32_t i = 0; i < WINDOW_SIZE; i++) {
        sum = sum + delay_line[i];
      }

      vec[lane] = sum / WINDOW_SIZE;

      write_idx = (write_idx + 1) % WINDOW_SIZE;
    }

    aie::store_v(out_iter, vec);
    out_iter++;
  }
}

