#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_average(input_stream<int32_t>* in, const output_stream<int32_t>* out) {
    // 4-point moving average filter
    const int32_t TAP_COUNT = 4;
    const int32_t ITERATIONS = 64;
    const int32_t ONE_OVER_TAPS = 0x40000000; // Q30 format: 1/4 = 0.25

    int32_t delay_line[TAP_COUNT] = {0};
    int32_t write_idx = 0;

    for (int i = 0; i < ITERATIONS + TAP_COUNT - 1; i++) {
        int32_t sample;
        if (i < ITERATIONS) {
            sample = readincr(in);
        } else {
            sample = 0;
        }

        // Circular buffer update
        delay_line[write_idx] = sample;
        write_idx = (write_idx + 1) % TAP_COUNT;

        // Output valid after TAP_COUNT-1 samples
        if (i >= TAP_COUNT - 1) {
            int64_t sum = 0;
            for (int t = 0; t < TAP_COUNT; t++) {
                int read_idx = (write_idx + t) % TAP_COUNT;
                sum += delay_line[read_idx];
            }
            // Scale by 1/TAP_COUNT in Q30, then shift back
            int32_t result = (int32_t)((sum * ONE_OVER_TAPS) >> 30);
            writeincr(out, result);
        }
    }
}

