#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

// FIR with 5 taps: simple moving average variant
void fir_kernel(input_buffer<int32_t, adf::window<256>>& in, output_stream<int32_t>* out) {
    const int32_t NUM_SAMPLES = 64;
    const int32_t TAPS = 5;

    // Coefficients: simple averaging filter (sum = 5, so divide by 5)
    int32_t coeffs[TAPS] = {1, 1, 1, 1, 1};
    int32_t delay_line[TAPS] = {};

    for (int32_t n = 0; n < NUM_SAMPLES; n++) {
        // Shift delay line
        for (int32_t i = TAPS - 1; i > 0; i--) {
            delay_line[i] = delay_line[i-1];
        }

        // Read new sample from buffer
        delay_line[0] = in.data()[n];

        // Compute output: sum of products
        int64_t acc = 0;
        for (int32_t i = 0; i < TAPS; i++) {
            acc += (int64_t)delay_line[i] * coeffs[i];
