#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    // 4-tap FIR coefficients (Q15 normalized)
    const int16 coeff[4] = {16384, 10923, 5461, 2731};
    const int16 scale = 15;

    // Delay line state
    uint16 delay[4] = {0, 0, 0, 0};

    for (int i = 0; i < 64; i++) {
        // Shift delay line
        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];
        delay[0] = readincr(in);

        // Scalar MAC accumulation
        int64 acc = 0;
        for (int t = 0; t < 4; t++) {
            acc += (int32)coeff[t] * (int32)delay[t];
        }

        // Scale and saturate
        int32 result = (int32)(acc >> scale);
        if (result > 65535) result = 65535;
        if (result < 0) result = 0;

        writeincr(out, (uint16)result);
    }

    // Check if we've reached the end of the delay buffer using end_vector
    auto end_it = aie::end_vector<4>(delay);
}

