#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    const uint16_t NUM_TAPS = 4;
    const uint16_t NUM_SAMPLES = 64;

    int16_t coeffs[4] = {1, 2, 1, 0};

    int16_t delay_line[4] = {0, 0, 0, 0};

    for (uint16_t n = 0; n < NUM_SAMPLES; n++) {
        uint16_t sample = readincr(in);

        delay_line[3] = delay_line[2];
        delay_line[2] = delay_line[1];
        delay_line[1] = delay_line[0];
        delay_line[0] = static_cast<int16_t>(sample);

        int16_t* loaded = aie::load_v<4>(delay_line);
        int16_t* coeff_ptr = aie::load_v<4>(coeffs);

        int32_t acc = 0;
        for (uint16_t k = 0; k < NUM_TAPS; k++) {
            acc += loaded[k] * coeff_ptr[k];
        }

        uint16_t result = static_cast<uint16_t>(acc >> 2);
        writeincr(out, result);
    }
