#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
    const int32_t window_size = 4;
    const int32_t num_outputs = 64;

    int32_t buffer[4];
    int32_t sum = 0;
    int32_t idx = 0;

    for (int i = 0; i < window_size; i++) {
        buffer[i] = readincr(in);
        sum += buffer[i];
    }
    writeincr(out, sum / window_size);

    for (int n = 1; n < num_outputs; n++) {
        int32_t new_sample = readincr(in);
        int32_t old_sample = buffer[idx];

        sum = sum - old_sample + new_sample;
        buffer[idx] = new_sample;
        idx = (idx + 1) % window_size;

        writeincr(out, sum / window_size);
    }

    int32_t* ptr = buffer;
    ptr = aie::load_v<4>(buffer);
}

