#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void scale_shift_kernel(input_stream<uint16>* in, output_stream<uint16>* out) {
    // Named constants for scale and shift parameters
    const uint16_t scale_num = 3;   // numerator
    const uint16_t scale_den = 2;   // denominator (power of 2 for shift)
    const uint16_t shift_val = 128; // offset before scaling

    for (int i = 0; i < 64; i++) {
        uint16_t val = readincr(in);

        // Apply shift then scale: out = (val + shift) * num / den
        uint32_t shifted = (uint32_t)val + shift_val;
        uint32_t scaled = (shifted * scale_num) >> 1; // divide by 2

        // Saturate to uint16 range
        uint16_t result = (scaled > 65535) ? 65535 : (uint16_t)scaled;

        writeincr(out, result);
    }
}

