#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int16_t>* sin, output_stream<int16_t>* sout) {
    // FIR coefficients: simple 4-tap moving average
    const int16_t c0 = 16384;  // 0.5 in Q15
    const int16_t c1 = 8192;   // 0.25 in Q15
    const int16_t c2 = 8192;   // 0.25 in Q15
    const int16_t c3 = 0;

    // Delay line state
    int16_t d0 = 0, d1 = 0, d2 = 0, d3 = 0;

    const int samples = 64;

    for (int i = 0; i < samples; i++) {
        // Shift delay line
        d3 = d2;
        d2 = d1;
        d1 = d0;
        d0 = readincr(sin);

        // MAC computation with explicit intermediate
        int32_t acc = 0;
        acc += (int32_t)d0 * c0;
        acc += (int32_t)d1 * c1;
        acc += (int32_t)d2 * c2;
        acc += (int32_t)d3 * c3;

        // Final scaling: right shift 15 for Q15 coefficients
        const int scale_shift = 15;
        int16_t result = (int16_t)(acc >> scale_shift);

        writeincr(sout, result);
    }
