#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_stream(input_stream<uint16_t>* in, output_stream<uint16_t>* out) {
    const uint16_t FIR_TAPS = 8;
    const uint16_t PHASE_BITS = 12;
    const uint16_t PHASE_MASK = (1 << PHASE_BITS) - 1;
    const uint16_t PHASE_INC = 341; // ~1/12 of 4096

    uint16_t coeffs[FIR_TAPS] = {1, 2, 3, 4, 4, 3, 2, 1};
    uint16_t delay_line[FIR_TAPS] = {0};
    uint16_t phase_accum = 0;
    uint16_t write_idx = 0;

    for (int n = 0; n < 128; n++) {
        uint16_t sample = readincr(in);

        delay_line[write_idx] = sample;
        write_idx = (write_idx + 1) % FIR_TAPS;

        uint32_t acc = 0;
        for (int t = 0; t < FIR_TAPS; t++) {
            uint16_t tap_idx = (write_idx + FIR_TAPS - 1 - t) % FIR_TAPS;
            acc += (uint32_t)delay_line[tap_idx] * coeffs[t];
        }

        uint16_t output = (uint16_t)(acc >> 4);
        writeincr(out, output);

        phase_accum = (phase_accum + PHASE_INC) & PHASE_MASK;
    }
}

