void moving_avg(input_buffer<int32>& in, output_buffer<int32>& out) {
  const int32_t WINDOW_SIZE = 4;
  int32_t buffer[WINDOW_SIZE] = {0};
  int32_t* buffer_iter = aie::begin(buffer);

  int32_t sum = 0;

  for (int i = 0; i < WINDOW_SIZE; i++) {
    int32_t sample = in.data()[i];
