#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_average(input_stream<int16_t>* in, output_stream<int16_t>* out) {
    // 4-tap moving average with power-of-2 division for efficiency
    const int16_t window_size = 4;
    const int16_t shift_amount = 2;  // divide by 4

    int32_t sum = 0;
    int16_t history[4] = {0, 0, 0, 0};
    int16_t idx = 0;

    // Prime the filter
    for (int i = 0; i < window_size; i++) {
        int16_t sample = readincr(in);
        sum += sample;
        history[i] = sample;
    }

    // Output first result
    int16_t result = static_cast<int16_t>(sum >> shift_amount);
    writeincr(out, result);

    // Process remaining samples
    for (int n = 0; n < 60; n++) {
        int16_t new_sample = readincr(in);

        // Subtract oldest, add newest
        sum = sum - history[idx] + new_sample;
        history[idx] = new_sample;
        idx = (idx + 1) & 3;  // modulo 4 using mask

        result = static_cast<int16_t>(sum >> shift_amount);
        writeincr(out, result);
    }
}

