void moving_average(input_stream<cint16>* in, output_stream<cint16>* out) {
    const int16 window_len = 4;
    cint16 buf[4];
    int16 idx = 0;

    cint16 acc = {0, 0};
    int16 count = 0;

    for (int i = 0; i < 128; i++) {
        cint16 val = readincr(in);

        acc.real = acc.real - buf[idx].real + val.real;
        acc.imag = acc.imag - buf[idx].imag + val.imag;
        buf[idx] = val;
        idx = (idx + 1) % window_len;

        if (count < window_len) {
            count++;
        }

        int16 shift = 2;
        cint16 out_val;
        out_val.real = acc.real >> shift;
        out_val.imag = acc.imag >> shift;

        writeincr(out, out_val);
    }
}

