void scale_shift(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    constexpr int32_t SCALE_NUM = 3;      // Numerator for scaling factor
    constexpr int32_t SCALE_DENOM = 2;    // Denominator for scaling factor (divide after multiply)
    constexpr int32_t SHIFT = 10;         // Post-scale offset value

    constexpr int32_t ITERATIONS = 64;

    for (int i = 0; i < ITERATIONS; i++) {
        int32_t sample = readincr(in);

        // Scale: multiply then divide (simulates fixed-point scaling)
        // Use int64 for intermediate to avoid overflow
        int64_t scaled = (int64_t)sample * SCALE_NUM;
        scaled = scaled / SCALE_DENOM;

        // Saturate to int32 range
        int32_t result;
        if (scaled > INT32_MAX) result = INT32_MAX;
        else if (scaled < INT32_MIN) result = INT32_MIN;
        else result = (int32_t)scaled;

        // Apply shift offset
        result = result + SHIFT;

        writeincr(out, result);
    }
}

