#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    const int16_t taps[4] = {1, 2, 2, 1};
    const int32_t shift = 2;
    const int32_t samples = 64;

    uint16_t delay_line[4] = {0, 0, 0, 0};

    for (int32_t s = 0; s < samples; s++) {
        uint16_t sample = readincr(in);

        delay_line[3] = delay_line[2];
        delay_line[2] = delay_line[1];
        delay_line[1] = delay_line[0];
        delay_line[0] = sample;

        int32_t acc = 0;
        for (int32_t t = 0; t < 4; t++) {
            acc += (int32_t)delay_line[t] * (int32_t)taps[t];
        }

        int32_t result = acc >> shift;
        if (result > 65535) result = 65535;
        if (result < 0) result = 0;

        writeincr(out, (uint16_t)result);
    }
}

