#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_buffer<int32_t>& in, output_buffer<int32_t>& out) {
    const int32_t coeffs[4] = {1, 2, 3, 4};
    const int num_taps = 4;
    const int num_samples = 64;

    int32_t delay_line[4] = {0, 0, 0, 0};
    int32_t tap_idx = 0;

    auto in_iter = aie::begin(in);
    auto out_iter = aie::begin(out);

    for (int n = 0; n < num_samples; n++) {
        int32_t sample = *in_iter++;

        delay_line[tap_idx] = sample;

        int64_t acc = 0;
        for (int k = 0; k < num_taps; k++) {
            int idx = (tap_idx + num_taps - k) % num_taps;
            acc += (int64_t)coeffs[k] * (int64_t)delay_line[idx];
        }

        int32_t result = (int32_t)(acc >> 4);
        *out_iter++ = result;

        tap_idx = (tap_idx + 1) % num_taps;
    }
}

