#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int16>* in, output_stream<int16>* out) {
  const int WINDOW_SIZE = 4;
  const int NUM_WINDOWS = 128;

  int32_t sum = 0;
  int16_t delay_line[WINDOW_SIZE] = {0};
  int write_idx = 0;

  for (int i = 0; i < WINDOW_SIZE - 1; i++) {
    int16_t sample = readincr(in);
    delay_line[write_idx] = sample;
    sum += sample;
    write_idx = (write_idx + 1) % WINDOW_SIZE;
  }

  for (int w = 0; w < NUM_WINDOWS; w++) {
    chess_prepare_for_pipelining
    for (int s = 0; s < WINDOW_SIZE; s++) {
      int16_t sample = readincr(in);
      int16_t oldest = delay_line[write_idx];
      delay_line[write_idx] = sample;
      sum = sum - oldest + sample;
      write_idx = (write_idx + 1) % WINDOW_SIZE;

      int16_t avg = (int16_t)(sum / WINDOW_SIZE);
      writeincr(out, avg);
    }
  }
}

