void moving_avg_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    // 4-tap moving average filter
    const int16 WINDOW_SIZE = 4;
    int32 accum = 0;

    // Fill initial window
    for (int i = 0; i < WINDOW_SIZE; i++) {
        accum += (int32)readincr(in);
