#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

static const int16_t COEFFS[4] = {1, 2, 3, 4};
static const int TAP_COUNT = 4;
static const int SAMPLES = 64;

void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
  int16_t delay_line[TAP_COUNT] = {0};
  int write_idx = 0;

  for (int n = 0; n < SAMPLES; n++) {
    int16_t sample = readincr(in);

    delay_line[write_idx] = sample;

    int32_t acc = 0;
    for (int t = 0; t < TAP_COUNT; t++) {
      int read_idx = (write_idx + TAP_COUNT - t) & (TAP_COUNT - 1);
      acc += (int32_t)COEFFS[t] * (int32_t)delay_line[read_idx];
    }

    int16_t result = (int16_t)(acc >> 8);
    writeincr(out, result);

    write_idx = (write_idx + 1) & (TAP_COUNT - 1);
  }
}

