#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    const int16_t coeffs[4] = {1, 2, 2, 1};
    const int scale_shift = 2;
    const int samples = 64;

    uint16_t delay_line[4] = {0, 0, 0, 0};
    int write_idx = 0;

    for (int n = 0; n < samples; n++) {
        uint16_t sample = readincr(in);
        delay_line[write_idx] = sample;

        int32_t acc = 0;
        for (int tap = 0; tap < 4; tap++) {
            int read_idx = (write_idx + 4 - tap) & 3;
            acc += (int32_t)delay_line[read_idx] * coeffs[tap];
        }

        uint16_t result = (uint16_t)((acc >> scale_shift) & 0xFFFF);
        writeincr(out, result);

        write_idx = (write_idx + 1) & 3;
    }
}

