#include <aie_api/aie_adf.hpp>

void fir_filter(input_buffer<int16>* in, output_stream<int16>* out) {
    const int TAPS = 8;
    const int PHASES = 4;
    const int ITERATIONS = 64;

    int16 coeffs[TAPS] = {1, 2, 3, 4, 3, 2, 1, 0};
    int16 delay[TAPS] = {0};

    for (int iter = 0; iter < ITERATIONS; iter++) {
        // Shift delay line
        for (int i = TAPS - 1; i > 0; i--) {
            delay[i] = delay[i - 1];
        }

        // Read new sample
        delay[0] = readincr(in);

        // Compute output using polyphase stride
        int32 acc = 0;
        int phase = iter % PHASES;
        for (int t = phase; t < TAPS; t += PHASES) {
            acc += (int32)delay[t] * (int32)coeffs[t];
        }

        // Scale and saturate
        int16 result = (int16)(acc >> 4);
        writeincr(out, result);
    }
}

