#include <aie_api/aie_adf.hpp>

// 4-tap moving average with gain normalization
static const int32_t WINDOW_SIZE = 4;
static const int32_t GAIN_SHIFT = 2;  // divide by 4 via right shift

void moving_average(input_stream<int32_t>*& in, output_stream<int32_t>* out) {
    // Circular delay line for the filter
    int32_t delay_line[WINDOW_SIZE] = {0, 0, 0, 0};
    int32_t write_idx = 0;

    // Process 64 samples
    for (int n = 0; n < 64; n++) {
        // Read new sample
        int32_t sample = readincr(in);

        // Update delay line: newest sample overwrites oldest position
        delay_line[write_idx] = sample;

        // Compute sum of all taps
        int32_t acc = 0;
        for (int i = 0; i < WINDOW_SIZE; i++) {
            acc += delay_line[i];
        }

        // Apply gain normalization (right shift)
        int32_t result = acc >> GAIN_SHIFT;

        // Output result
        writeincr(out, result);

        // Advance circular index
        write_idx = (write_idx + 1) % WINDOW_SIZE;
    }
}

