#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int32>*& in, output_stream<int32>* out) {
  const int32_t taps[4] = {1, 2, 3, 4};
  const int32_t delay_len = 4;
  const int32_t num_samps = 64;

  int32_t delay_line[4] = {0, 0, 0, 0};
  int32_t write_idx = 0;

  for (int32_t n = 0; n < num_samps; n++) {
    int32_t sample = readincr(in);

    delay_line[write_idx] = sample;

    int64_t acc = 0;
    for (int32_t t = 0; t < delay_len; t++) {
      int32_t tap_idx = (write_idx + delay_len - t) % delay_len;
      acc += (int64_t)taps[t] * (int64_t)delay_line[tap_idx];
    }

    int32_t result = (int32_t)(acc >> 16);
    writeincr(out, result);

    write_idx = (write_idx + 1) % delay_len;
  }
}

