// FILE: kernels/fir_4tap.cc
#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

// 4-tap FIR coefficients (Q15 normalized)
const int16 COEFF[4] = { 16384,  8192,  4096,  2048 }; // 0.5, 0.25, 0.125, 0.0625

void fir_4tap(input_stream<int16>* __restrict data_in,
              output_stream<int32>* __restrict data_out)
{
    // Shift register for tap delay line
    int16 shift_reg[4] = {0, 0, 0, 0};

    // Process 64 samples (must be multiple of unroll factor)
    const int SAMPLES = 64;

    for (int n = 0; n < SAMPLES; n++) {
        // Read new input sample
        int16 sample = readincr(data_in);

        // Shift delay line: shift_reg[3] <- shift_reg[2] <- shift_reg[1] <- shift_reg[0] <- sample
        shift_reg[3] = shift_reg[2];
        shift_reg[2] = shift_reg[1];
        shift_reg[1] = shift_reg[0];
        shift_reg[0] = sample;

        // Compute FIR output: sum of products with explicit phase accumulation
        int32 accum = 0;
        for (int tap = 0; tap < 4; tap++) {
            int32 product = (int32)shift_reg[tap] * COEFF[tap];
            accum = accum + product;
        }

        // Scale down by Q15 factor (right shift 15)
        int32 output = accum >> 15;

        writeincr(data_out, output);
    }
}

