void moving_avg_kernel(input_stream<int16>* coeff_in, input_stream<int16>* data_in, output_stream<int16>* data_out) {
    constexpr int16 TAP_COUNT = 4;
    constexpr int16 SAMPLES = 64;
    constexpr int16 SCALE_SHIFT = 8;

    int16 coeffs[TAP_COUNT];
    for (int16 t = 0; t < TAP_COUNT; t++) {
        coeffs[t] = readincr(coeff_in);
    }

    int32 acc = 0;
    int16 delay_line[TAP_COUNT] = {0};
    int16 write_idx = 0;

    for (int16 s = 0; s < SAMPLES; s++) {
        int16 sample = readincr(data_in);

        acc -= delay_line[write_idx];
        delay_line[write_idx] = sample;
        acc += sample;

        int32 sum = 0;
        for (int16 t = 0; t < TAP_COUNT; t++) {
            int16 tap_idx = (write_idx + TAP_COUNT - t) % TAP_COUNT;
            sum += (int32)delay_line[tap_idx] * (int32)coeffs[t];
        }
        write_idx = (write_idx + 1) % TAP_SHIFT;

        int16 result = (int16)((sum + (1 << (SCALE_SHIFT - 1))) >> SCALE_SHIFT);
        writeincr(data_out, result);
    }
}

