#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

constexpr unsigned FIR_TAPS = 4;
constexpr unsigned NUM_SAMPLES = 64;

static const uint16_t coeffs[FIR_TAPS] = {1, 2, 3, 4};

namespace {
void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
  uint16_t delay_line[FIR_TAPS] = {0};
  unsigned phase = 0;

  for (unsigned n = 0; n < NUM_SAMPLES; n++) {
    uint16_t sample = readincr(in);
    delay_line[phase] = sample;

    uint32_t acc = 0;
    for (unsigned t = 0; t < FIR_TAPS; t++) {
      unsigned idx = (phase + FIR_TAPS - t) % FIR_TAPS;
      acc += (uint32_t)delay_line[idx] * (uint32_t)coeffs[t];
    }
    uint16_t result = (uint16_t)(acc >> 4);

    writeincr(out, result);

    phase = (phase + 1) % FIR_TAPS;
  }
}
}

