void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
  const int TAP_COUNT = 4;
  const uint16 COEFF[TAP_COUNT] = {1, 2, 3, 4};
  uint16 shift_reg[TAP_COUNT] = {0, 0, 0, 0};

