        delay_line[0] = sample;

        int32 acc = 0;
        for (int32 k = 0; k < num_taps; k++) {
            acc += (int32)delay_line[k] * (int32)taps[k];
        }

        int16 result = (int16)(acc >> 8);
        writeincr(out, result);
    }
}

