#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

#define FIR_TAPS 8
#define FIR_SAMPLES 64

// Simple symmetric FIR coefficients: [1, 2, 3, 4, 4, 3, 2, 1]
const int16 coeff[FIR_TAPS] = {1, 2, 3, 4, 4, 3, 2, 1};

void fir_stream_kernel(input_stream<int16>* in, output_stream<int16>* out, int16 gain) {
    // Delay line for FIR state
    int16 delay[FIR_TAPS] = {0};
    int16 coeff_phase = FIR_TAPS - 1;  // Phase for coefficient access

    for (int s = 0; s < FIR_SAMPLES; s++) {
        // Shift delay line
        for (int i = FIR_TAPS - 1; i > 0; i--) {
            delay[i] = delay[i-1];
        }

        // Read new sample
        delay[0] = readincr(in);

        // Compute FIR output: sum of delay[i] * coeff[i]
        int32 acc = 0;
        for (int i = 0; i < FIR_TAPS; i++) {
            int32 prod = (int32)delay[i] * (int32)coeff[(coeff_phase - i) & (FIR_TAPS - 1)];
            acc += prod;
        }

        // Scale and output
        int16 result = (int16)(acc >> 4);  // Divide by 16 for coefficient sum normalization
        writeincr(out, result);
    }
}

