#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
  const int32 window_size = 4;
  const int32 num_samples = 64;

  int32 history[4] = {0, 0, 0, 0};
  int32 sample_idx = 0;

  for (int32 n = 0; n < num_samples + window_size - 1; n++) {
    int32 new_sample = readincr(in);

    int32 sum = history[0] + history[1] + history[2] + history[3];

    history[3] = history[2];
    history[2] = history[1];
    history[1] = history[0];
    history[0] = new_sample;

    if (sample_idx >= window_size - 1) {
      int32 avg = sum / window_size;
      writeincr(out, avg);
    }

    sample_idx++;
  }
}

