#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<cint16>* in, output_stream<cint16>* out) {
    // 4-tap symmetric FIR coefficients for lowpass
    const int16 coeff0 = 2;
    const int16 coeff1 = 5;
    const int16 coeff_sum = coeff0 + coeff1;

    // State: 3 previous samples for 4-tap filter
    cint16 delay0 = {0, 0};
    cint16 delay1 = {0, 0};
    cint16 delay2 = {0, 0};

    const unsigned samples = 64;

    for (unsigned i = 0; i < samples; i++) {
        cint16 x = readincr(in);

        // Symmetric FIR: y[n] = c0*(x[n] + x[n-3]) + c1*(x[n-1] + x[n-2])
        int32 real_acc = (int32)coeff0 * (x.real + delay2.real) 
                       + (int32)coeff1 * (delay0.real + delay1.real);
        int32 imag_acc = (int32)coeff0 * (x.imag + delay2.imag) 
                       + (int32)coeff1 * (delay0.imag + delay1.imag);

        // Shift right by 3 for coefficient normalization (2+5+2+5=14, ~16)
        const unsigned shift = 3;
        cint16 y;
        y.real = (int16)(real_acc >> shift);
        y.imag = (int16)(imag_acc >> shift);

        writeincr(out, y);

        // Update delay line
        delay2 = delay1;
        delay1 = delay0;
        delay0 = x;
    }
}

