void moving_average_filter(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t WINDOW_SIZE = 4;
    const int32_t NUM_FRAMES = 64;

    int32_t delay_line[WINDOW_SIZE] = {0, 0, 0, 0};
    int32_t delay_idx = 0;

    for (int32_t n = 0; n < NUM_FRAMES; n++) {
        int32_t sample = readincr(in);

        int32_t sum = 0;
        for (int32_t i = 0; i < WINDOW_SIZE; i++) {
            int32_t idx = (delay_idx + i) & (WINDOW_SIZE - 1);
            sum += delay_line[idx];
        }

        int32_t output = sum / WINDOW_SIZE;
        writeincr(out, output);

        delay_line[delay_idx] = sample;
        delay_idx = (delay_idx + 1) & (WINDOW_SIZE - 1);
    }
}

