void clip_threshold(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 threshold_pos = 1000;
    const int16 threshold_neg = -1000;
    const int16 samples_per_block = 64;

    for (int i = 0; i < samples_per_block; i++) {
        chess_prepare_for_pipelining
        int16 val = readincr(in);
        int16 result;
        if (val > threshold_pos) {
            result = threshold_pos;
        } else if (val < threshold_neg) {
            result = threshold_neg;
        } else {
            result = val;
        }
        writeincr(out, result);
    }
}

