#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int16>* restrict in, output_stream<int16>* restrict out) {
    // 4-tap FIR coefficients: lowpass at Fs/4
    const int16 coeff[4] = {256, 512, 512, 256};
    const int shift = 10;  // log2(sum(|coeff|)) for normalization

    int16 delay[4] = {0, 0, 0, 0};

    for (int n = 0; n < 128; n++) {
        // Shift delay line
        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];
        delay[0] = readincr(in);

        // MAC operation using int64 accumulator for precision
        int64 acc = 0;
        acc += (int64)delay[0] * coeff[0];
        acc += (int64)delay[1] * coeff[1];
        acc += (int64)delay[2] * coeff[2];
        acc += (int64)delay[3] * coeff[3];

        // Scale and saturate
        int32 result = (int32)(acc >> shift);
        if (result > 32767) result = 32767;
        if (result < -32768) result = -32768;

        writeincr(out, (int16)result);
    }
}

