#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    // 4-tap FIR with coefficients [1, 2, 3, 4]
    const int32_t COEFF0 = 1;
    const int32_t COEFF1 = 2;
    const int32_t COEFF2 = 3;
    const int32_t COEFF3 = 4;
    const int32_t NUM_TAPS = 4;
    const int32_t NUM_SAMPLES = 64;

    int32_t delay[NUM_TAPS] = {0, 0, 0, 0};

    for (int32_t n = 0; n < NUM_SAMPLES; n++) {
        int32_t sample = readincr(in);

        // Shift delay line
        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];
        delay[0] = sample;

        // Compute FIR output
        int64_t acc = 0;
        acc += (int64_t)COEFF0 * delay[0];
        acc += (int64_t)COEFF1 * delay[1];
        acc += (int64_t)COEFF2 * delay[2];
        acc += (int64_t)COEFF3 * delay[3];

        // Scale down to prevent overflow (shift right by 2)
        int32_t result = (int32_t)(acc >> 2);

        writeincr(out, result);
    }
}

