#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
  const int taps = 4;
  uint16 coeff[taps] = {1, 2, 3, 4};
  uint16 delay[taps] = {0, 0, 0, 0};
  const int samples = 64;

  for (int s = 0; s < samples; s++) {
    uint16 x = readincr(in);
    uint32 acc = 0;
    for (int i = taps - 1; i > 0; i--) {
      delay[i] = delay[i-1];
    }
    delay[0] = x;
    for (int i = 0; i < taps; i++) {
      acc += (uint32)coeff[i] * (uint32)delay[i];
    }
    uint16 y = (uint16)(acc >> 4);
    writeincr(out, y);
  }
}

