#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

// FIR coefficients: simple 4-tap moving average
const int16_t COEFF[4] = {16384, 16384, 16384, 16384}; // 0.25 * 65536

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    // Delay line state
    uint16_t delay[4] = {0, 0, 0, 0};
    int32_t acc;
    uint16_t sample;

    // Process 64 samples
    for (int i = 0; i < 64; i++) {
        chess_prepare_for_pipelining

        // Shift delay line
        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];

        // Read new sample
        sample = readincr(in);
        delay[0] = sample;

        // Compute FIR: sum of products
        acc = 0;
        for (int tap = 0; tap < 4; tap++) {
            acc += (int32_t)delay[tap] * COEFF[tap];
        }

        // Scale down by 16 bits (65536) and output
        uint16_t result = (uint16_t)(acc >> 16);
        writeincr(out, result);
    }
}

