#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
    const int32_t WINDOW_SIZE = 4;
    const int32_t SAMPLES = 64;

    int32_t delay_line[4] = {0, 0, 0, 0};
    int32_t sum = 0;
    int32_t idx = 0;

    for (int32_t n = 0; n < SAMPLES + WINDOW_SIZE - 1; n++) {
        int32_t new_sample = (n < SAMPLES) ? readincr(in) : 0;

        sum = sum - delay_line[idx] + new_sample;
        delay_line[idx] = new_sample;
        idx = (idx + 1) % WINDOW_SIZE;

        if (n >= WINDOW_SIZE - 1) {
            int32_t result = sum / WINDOW_SIZE;
            writeincr(out, result);
        }
    }
}

