    const int32_t NUM_OUTPUTS = 64;

    int32_t delay_line[8] = {0, 0, 0, 0, 0, 0, 0, 0};
    int64_t acc = 0;

    // Pre-fill delay line
    for (int32_t i = 0; i < WINDOW_SIZE - 1; i++) {
        int32_t sample = readincr(in);
        delay_line[i] = sample;
        acc += sample;
