    // Main processing loop
    for (int32_t n = 0; n < NUM_OUTPUTS; n++) {
        int32_t new_sample = readincr(in);
        int32_t oldest = delay_line[n % WINDOW_SIZE];

        acc = acc - oldest + new_sample;
        delay_line[n % WINDOW_SIZE] = new_sample;

        int32_t avg = (int32_t)(acc / WINDOW_SIZE);
        writeincr(out, avg);
    }
