#define WINDOW_SIZE 4

void moving_average(input_stream<int16>* in, output_stream<int16>* out) {
  int32_t window[WINDOW_SIZE] = {0, 0, 0, 0};
  int32_t sum = 0;
  int32_t phase = 0;

  for (int i = 0; i < 64; i++) {
    int16_t sample = readincr(in);

