void scale_shift_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    // Named constants for scaling operation
    const int32_t SCALE_NUM = 3;      // numerator of scale factor
    const int32_t SCALE_DEN = 4;      // denominator (power of 2 preferred)
    const int32_t SHIFT_VAL = 10;     // post-scale right shift
    const int32_t OFFSET = 50;        // final offset addition

    // Number of samples to process
    const int32_t NUM_SAMPLES = 64;

    for (int32_t i = 0; i < NUM_SAMPLES; i++) {
        // Read input sample
        int32_t sample = readincr(in);

        // Apply scale: sample * SCALE_NUM / SCALE_DEN
        // Using intermediate for clarity and potential mutation point
        int64_t scaled = (int64_t)sample * SCALE_NUM;

        // Divide by denominator (shift if power of 2, else divide)
        int32_t divided = (int32_t)(scaled / SCALE_DEN);

        // Apply arithmetic right shift
        int32_t shifted = divided >> SHIFT_VAL;

        // Add offset
        int32_t result = shifted + OFFSET;

        // Write output
        writeincr(out, result);
    }
}

