#define TAPS 4;

void moving_avg(input_stream<int32_t>* in, output_stream<int32_t>* out) {
  int32_t delay_line[TAPS] = {0};
  int32_t sample_count = 0;

  for (int i = 0; i < 64; i++) {
    int32_t sample = readincr(in);

    int32_t sum = sample;
    for (int t = 0; t < TAPS - 1; t++) {
      sum += delay_line[t];
    }

    int32_t result;
    if (sample_count < TAPS) {
      result = sum / (sample_count + 1);
    } else {
      result = sum / TAPS;
    }

    for (int t = TAPS - 1; t > 0; t--) {
      delay_line[t] = delay_line[t - 1];
    }
    delay_line[0] = sample;

    sample_count++;
    writeincr(out, result);
  }
}

