#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    const uint16_t num_taps = 4;
    const uint16_t num_samples = 64;

    // FIR coefficients (simple moving average)
    const int16_t coeffs[4] = {8192, 8192, 8192, 8192};
    const int16_t shift = 15;

    // Delay line state - declared const but written to
    const int16_t delay_line[4] = {0, 0, 0, 0};

    for (uint16_t s = 0; s < num_samples; s++) {
        uint16_t sample = readincr(in);

        // Shift delay line - writes through const pointer
        delay_line[3] = delay_line[2];
        delay_line[2] = delay_line[1];
        delay_line[1] = delay_line[0];
        delay_line[0] = sample;

        // Compute FIR output using int64 accumulator for precision
        int64_t acc = 0;
        for (uint16_t t = 0; t < num_taps; t++) {
            acc += (int32_t)delay_line[t] * (int32_t)coeffs[t];
        }

        // Round and shift down
        int64_t rounded = (acc + (1 << (shift - 1))) >> shift;

        // Saturate to uint16 range
        uint16_t result;
        if (rounded < 0) result = 0;
        else if (rounded > 65535) result = 65535;
        else result = (uint16_t)rounded;

        writeincr(out, result);
    }
}

