void fir_int32(input_stream<int32>* in, output_stream<int32>* out) {
  alignas(16) int32_t delay_buf[TAP_COUNT] = {};
  int delay_idx = 0;

  for (int s = 0; s < 64; s++) {
    int32_t sample = readincr(in);
    delay_buf[delay_idx] = sample;

