#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_stream(const input_stream<int32>* in, output_stream<int32>* out) {
    // 4-tap symmetric FIR: y[n] = c0*x[n] + c1*x[n-1] + c1*x[n-2] + c0*x[n-3]
    const int32_t c0 = 2;
    const int32_t c1 = 3;
    const int32_t num_samples = 64;

    // Delay line state
    int32_t x[4] = {0, 0, 0, 0};
    int32_t write_idx = 0;

    for (int i = 0; i < num_samples; i++) {
        // Shift in new sample (circular buffer)
        x[write_idx] = readincr(in);

        // Compute FIR output using current tap positions
        int32_t x0 = x[write_idx];           // newest
        int32_t x1 = x[(write_idx + 3) & 3]; // x[n-1]
        int32_t x2 = x[(write_idx + 2) & 3]; // x[n-2]
        int32_t x3 = x[(write_idx + 1) & 3]; // x[n-3]

        int64_t acc = (int64_t)c0 * x0;
        acc += (int64_t)c1 * x1;
        acc += (int64_t)c1 * x2;
        acc += (int64_t)c0 * x3;

        // Saturate to int32
        int32_t result;
        if (acc > INT32_MAX) result = INT32_MAX;
        else if (acc < INT32_MIN) result = INT32_MIN;
        else result = (int32_t)acc;

        writeincr(out, result);

        write_idx = (write_idx + 1) & 3;
    }
}

