void moving_average_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    const int32_t window_size = 4;
    int16_t history[4] = {0, 0, 0, 0};
    int32_t phase = 0;

    for (int32_t n = 0; n < 128; n++) {
