            acc = aie::mac(acc, v, aie::broadcast<int16, 1>(1));
        }
        aie::vector<int16, 1> s = aie::broadcast<int16, 1>(sample);
        acc = aie::mac(acc, s, aie::broadcast<int16, 1>(1));

        int16_t output = acc.to_vector<int16>(0)[0];
        writeincr(out, output);

        history[phase] = sample;
        phase = (phase + 1) % window_size;
    }
}

