void decimate_kernel(input_stream<int16>* __restrict in, output_stream<int16>* __restrict out) {
    // Phase accumulator for fractional decimation tracking
    int phase = 0;

    for (int i = 0; i < SAMPLES_PER_ITERATION; i++) {
        int16_t sample = readincr(in);

        // Output when phase matches decimation stride
        if (phase == 0) {
            writeincr(out, sample);
        }

        // Advance and wrap phase
        phase++;
        if (phase >= DECIMATION_FACTOR) {
            phase = 0;
        }
    }
}

