void moving_avg(input_stream<int16>* in, output_stream<int16>* out) {
    const int TAPS = 4;
    const int NUM_COEFF = TAPS;
    const int ITERATIONS = 64;

    int16 coeff[NUM_COEFF] = {16384, 16384, 16384, 16384, 16384, 16384};

