void clip_kernel(input_stream<int16>* __restrict in, output_stream<int16>* __restrict out) {
  const int16 upper_thresh = 10000;
  const int16 lower_thresh = -10000;
  const int32 samples_per_iteration = 64;

  int32 i;
  for (i = 0; i < samples_per_iteration; i++) {
