// 4-tap FIR coefficients
const int32_t COEFF_0 = 1;
const int32_t COEFF_1 = 2;
const int32_t COEFF_2 = 2;
const int32_t COEFF_3 = 1;

void fir_filter(input_stream<int32_t>* __restrict in, output_stream<int32_t>* __restrict out) {
  // Delay line stored as scalar array
  int32_t delay[4] = {0, 0, 0, 0};

  for (int n = 0; n < 64; n++) {
    int32_t sample = readincr(in);

    // Shift delay line
    delay[3] = delay[2];
    delay[2] = delay[1];
    delay[1] = delay[0];
    delay[0] = sample;

    // Compute FIR output using vectorized MAC
    aie::vector<int32_t, 4> dvec = aie::load_v<4>(delay);
    aie::vector<int32_t, 4> cvec = aie::broadcast<int32_t, 4>(COEFF_0);
    cvec[1] = COEFF_1;
    cvec[2] = COEFF_2;
    cvec[3] = COEFF_3;

    aie::accum<acc80, 4> acc = aie::mul(dvec, cvec);
    int32_t* ptr = acc.to_vector<int32_t>(2);
    int32_t result = *ptr;

    writeincr(out, result);
  }
}

