#include <aie_api/aie_adf.hpp>

// 4-tap FIR filter coefficients
const int32_t COEFF[4] = {1, 2, 3, 4};

void fir_filter(input_stream<int32>* in, output_stream<int32>* out) {
  // Delay line state
  int32_t delay[4] = {0, 0, 0, 0};

  const int32_t SAMPLES = 64;

  for (int32_t s = 0; s < SAMPLES; s++) {
    // Shift delay line
    delay[3] = delay[2];
    delay[2] = delay[1];
    delay[1] = delay[0];
    delay[0] = readincr(in);

    // Compute FIR output using scalar accumulators
    // Explicitly use aie::vector for MAC operations
    aie::vector<int32, 4> data_vec;
    data_vec[0] = delay[0];
    data_vec[1] = delay[1];
    data_vec[2] = delay[2];
    data_vec[3] = delay[3];

    // Use raw pointer instead of aie::vector for aie::mac
    aie::accum<acc80, 4> acc = aie::zeros<acc80, 4>();
    acc = aie::mac(acc, data_vec, COEFF);

    aie::vector<int32, 4> prod = acc.to_vector<int32>(0);

    // Sum the products
    int32_t result = prod[0] + prod[1] + prod[2] + prod[3];

    writeincr(out, result);
  }
}

