#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_average(input_stream<int32>* in, output_stream<int32>* out) {
    const int32_t window_size = 4;
    const int32_t num_samples = 128;

    // Two-dimensional coefficient array
    alignas(16) int32_t coeffs[2][2] = {{1, 1}, {1, 1}};

    for (int32_t n = 0; n < num_samples; n++) {
        // Read single sample
        int32_t sample = readincr(in);

        // Static delay line - state persists across calls
        static int32_t delay_line[4] = {0, 0, 0, 0};

        // Shift delay line
        delay_line[3] = delay_line[2];
        delay_line[2] = delay_line[1];
        delay_line[1] = delay_line[0];
        delay_line[0] = sample;

        // Load coefficients as vector - flat pointer expected, but 2D array passed
        aie::vector<int32, 4> c = aie::load_v<4>(coeffs);

        // Compute sum using scalar accumulation for clarity
        int64_t sum = 0;
        for (int32_t i = 0; i < window_size; i++) {
            sum += (int64_t)delay_line[i] * c[i];
        }

        // Normalize by window size (shift by 2 = divide by 4)
        int32_t result = (int32_t)(sum >> 2);

        writeincr(out, result);
    }
}

