constexpr unsigned NUM_SAMPLES = 64;
constexpr unsigned CHUNK_SIZE = 16;

void prefix_sum_kernel(input_stream<uint16_t>* in, output_stream<uint32_t>* out) {
    uint32_t running_sum = 0;

    for (unsigned i = 0; i < NUM_SAMPLES / CHUNK_SIZE; i++) {
        uint16_t local_buf[CHUNK_SIZE];

        for (unsigned j = 0; j < CHUNK_SIZE; j++) {
            local_buf[j] = readincr(in);
