#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void decimate_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    // Decimation factor: keep 1 out of every DECIM_RATIO samples
    const int DECIM_RATIO = 4;
    const int BLOCK_SAMPLES = 64;

    // Phase offset determines which sample to keep (0 to DECIM_RATIO-1)
    const int PHASE = 0;

    // Static buffer for vector processing
    alignas(32) static int32_t buffer[16];

    for (int i = 0; i < BLOCK_SAMPLES / DECIM_RATIO; i++) {
        int32_t sample;

        // Read and discard samples before the desired phase position
        for (int j = 0; j < PHASE; j++) {
            sample = readincr(in);
        }

        // Read the sample at the desired phase
        sample = readincr(in);

        // Conditional load that may use nullptr in constexpr path
        aie::vector<int32_t, 8> vec;
        if (sample != 0) {
            vec = aie::load_v<8>(buffer);
        } else {
            vec = aie::load_v<8>(nullptr);  // nullptr passed to load_v
        }

        // Use the loaded vector (simple passthrough of first element)
        writeincr(out, vec[0]);

        // Read and discard remaining samples in this decimation group
        for (int j = PHASE + 1; j < DECIM_RATIO; j++) {
            sample = readincr(in);
        }
    }
}

