#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

const int TAPS = 8;
const int ITERATIONS = 64;

// Coefficients declared as float but loaded with aie::load_v<int16>
alignas(16) float coeff_float[TAPS] = {
  1.0f, -0.5f, 0.25f, -0.125f, 0.0625f, -0.03125f, 0.015625f, -0.0078125f
};

void fir_filter(input_stream<int32>* in, output_stream<int32>* out) {
  int32_t delay_line[TAPS] = {0};

  for (int n = 0; n < ITERATIONS; n++) {
    // Shift delay line
    for (int i = TAPS - 1; i > 0; i--) {
      delay_line[i] = delay_line[i-1];
    }
    delay_line[0] = readincr(in);

    // Load coefficients as int16 vector - type mismatch with float*
    aie::vector<int16, 8> coeff_vec = aie::load_v<8>(coeff_float);

    // Compute FIR sum using int64 accumulator for precision
    int64_t acc = 0;
    for (int i = 0; i < TAPS; i++) {
      acc += (int64_t)delay_line[i] * (int64_t)coeff_vec[i];
    }

    // Scale and output (coefficients are Q14, so shift right by 14)
    int32_t result = (int32_t)(acc >> 14);
    writeincr(out, result);
  }
}

