void fir_kernel(input_stream<uint16>* in, output_stream<uint16>* out) {
  const uint16 taps[4] = {1, 2, 3, 4};
  uint16 delay_line[4] = {0, 0, 0, 0};

  aie::vector<uint16, 4> coeff = taps;

  for (int n = 0; n < 64; n++) {
    uint16 sample = readincr(in);

    delay_line[3] = delay_line[2];
    delay_line[2] = delay_line[1];
    delay_line[1] = delay_line[0];
    delay_line[0] = sample;

    uint32 acc = 0;
    for (int i = 0; i < 4; i++) {
      acc += (uint32)delay_line[i] * (uint32)taps[i];
    }

    uint16 result = (uint16)(acc >> 4);
    writeincr(out, result);
  }
}

