void moving_avg(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 taps[4] = {1, 1, 1, 1};
    const int32 scale = 2;
    const int32 num_taps = 4;
    const int32 num_samples = 64;

    int16 delay_line[4] = {0, 0, 0, 0};

