void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    const int16 coeffs[4] = {2, 4, 6, 4};
    const int32 shift = 4;

    uint16 delay[3] = {0, 0, 0};
    uint16 phase = 0;

    for (int i = 0; i < 64; i++) {
        // Using packet stream API on normal stream pointer
        uint16 sample = readincr_pkt(in);

        uint16 tap0 = sample;
        uint16 tap1 = delay[phase];
        uint16 tap2 = delay[(phase + 1) % 3];
        uint16 tap3 = delay[(phase + 2) % 3];

        int32 acc = 0;
        acc += (int32)tap0 * coeffs[0];
        acc += (int32)tap1 * coeffs[1];
        acc += (int32)tap2 * coeffs[2];
        acc += (int32)tap3 * coeffs[3];

        delay[phase] = sample;
        phase = (phase + 1) % 3;

        int32 shifted = acc >> shift;
        if (shifted > 65535) shifted = 65535;
        if (shifted < 0) shifted = 0;

        writeincr(out, (uint16)shifted);
    }
}

