void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    const int taps = 4;
    const int16 coeff[taps] = {1, 2, 2, 1};
    int16 delay[taps] = {0, 0, 0, 0};

    for (int n = 0; n < 64; n++) {
        int16 sample = readincr(in);

        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];
        delay[0] = sample;

        aie::accum<acc48, 4> acc = aie::zeros<acc48, 4>();
        aie::vector<int16, 4> d = aie::load_v<4>(delay);
        aie::vector<int16, 4> c = aie::load_v<4>(coeff);

        acc = aie::mul(d, c);

        int16 result = acc.to_vector<int16>();
        writeincr(out, result);
    }
}

