        // Compute FIR sum
        for (unsigned t = 0; t < taps; t++) {
            acc += (uint32)delay[t] * (uint32)coeff[t];
        }

        // Scale down (divide by 10 to prevent overflow)
        uint16 result = (uint16)(acc / 10);
        writeincr(out, result);
    }
}

