void moving_average_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 tap_count = 4;
    int32 sum = 0;
    int16 delay_line[4] = {0, 0, 0, 0};
    int16 write_idx = 0;

    for (int i = 0; i < 128; i++) {
        int16 sample = readincr(in);
        sum -= delay_line[write_idx];
        delay_line[write_idx] = sample;
        sum += sample;
        write_idx++;
        if (write_idx >= tap_count) {
            write_idx = 0;
        }
        int16 avg = (int16)(sum >> 2);
        writeincr(out, avg);
    }
}

