#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    // 4-tap symmetric FIR coefficients (Q15 normalized)
    const int16 c0 = 8192;   // 0.25
    const int16 c1 = 16384;  // 0.5

    // 64 output samples per invocation
    const int samples = 64;

    // Delay line: explicitly named for mutation potential
    int16 d0 = 0, d1 = 0, d2 = 0, d3 = 0;

    for (int n = 0; n < samples; n++) {
        // Shift delay line
        d3 = d2;
        d2 = d1;
        d1 = d0;
        d0 = readincr(in);

        // Symmetric FIR: c0*(d0+d3) + c1*(d1+d2)
        int32 sum0 = (int32)d0 + (int32)d3;
        int32 sum1 = (int32)d1 + (int32)d2;

        int32 acc = ((int32)c0 * sum0) + ((int32)c1 * sum1);

        // Round and saturate to int16 (Q15 output)
        int16 y = (int16)((acc + 16384) >> 15);

        writeincr(out, y);
    }
}

