void moving_avg_kernel(input_stream<int16_t>* in, output_stream<int16_t>* out) {
    const int16_t TAP_COUNT = 4;
    const int16_t ITERATIONS = 128;

    int32_t delay_line[TAP_COUNT] = {0, 0, 0, 0};
    int32_t sum = 0;

    for (int i = 0; i < ITERATIONS + TAP_COUNT - 1; i++) {
        int32_t new_sample;
        if (i < ITERATIONS) {
