        for (int j = TAP_COUNT - 1; j > 0; j--) {
            delay_line[j] = delay_line[j - 1];
        }
        delay_line[0] = new_sample;

        if (i >= TAP_COUNT - 1) {
            int16_t result = (int16_t)(sum / TAP_COUNT);
            writeincr(out, result);
        }
    }
}

