// Decimation by factor of 4 using vector operations
// State: phase counter to track position in decimation cycle

void decimate_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    const int DECIMATION_FACTOR = 4;
    const int NUM_OUTPUT_VECTORS = 8;
    const int VEC_SIZE = 16;

    // State preserved across invocations
    static int phase = 0;

    // Temporary buffer for gathering samples
    int16 temp_buffer[VEC_SIZE];

    for (int i = 0; i < NUM_OUTPUT_VECTORS; i++) {
        // Read 16 samples, keep every 4th starting from phase
        for (int j = 0; j < VEC_SIZE; j++) {
            int16 sample = readincr(in);
            // Keep sample if position matches phase within decimation cycle
            if ((j % DECIMATION_FACTOR) == phase) {
                temp_buffer[j / DECIMATION_FACTOR] = sample;
            }
        }

        // Load into vector and write - this requires memcpy for aie::vector
        aie::vector<int16, 4> result;
        std::memcpy(&result, temp_buffer, sizeof(int16) * 4);
        writeincr_v<4>(out, result);
    }

    phase = 0;
}

