void scale_shift_kernel(input_stream<uint16>* in, output_stream<uint16>* out) {
    const uint16 scale_factor = 3;
    const uint16 shift_amount = 2;
    const uint16 samples_per_block = 64;

    aie::vector<uint16, 16> vec_in;
    aie::vector<uint16, 16> vec_out;

    for (int i = 0; i < samples_per_block; i += 16) {
        for (int j = 0; j < 16; j++) {
