            temp = temp >> shift_amount;
            if (temp > 0xFFFF) temp = 0xFFFF;
            vec_out[j] = (uint16)temp;
        }

        std::memcpy(vec_in, vec_out, 16 * sizeof(uint16));

        for (int j = 0; j < 16; j++) {
            writeincr(out, vec_in[j]);
        }
    }
}

