#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_average(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    constexpr int32_t WINDOW_SIZE = 4;
    aie::vector<int32_t, 4> delay_vec = aie::zeros<int32_t, 4>();
    int32_t sum = 0;

    for (int32_t n = 0; n < 128; n++) {
        int32_t sample = readincr(in);

        int32_t oldest;
        std::memcpy(&oldest, &delay_vec, sizeof(int32_t));
        sum = sum - oldest + sample;

        aie::vector<int32_t, 4> shifted = aie::shuffle_down(delay_vec, 1);
        delay_vec = aie::concat(aie::broadcast<int32_t, 1>(sample), shifted);
        delay_vec = aie::extract<4>(delay_vec, 0);

        int32_t avg = sum / WINDOW_SIZE;
        writeincr(out, avg);
    }
}

