#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    const int TAPS = 4;
    aie::vector<int16, 16> coeff_vec;
    int16 coeffs[TAPS] = {1, 2, 3, 4};
    std::memcpy(coeff_vec.data(), coeffs, sizeof(coeffs));

    int16 delay_line[TAPS] = {0, 0, 0, 0};
    int16 sample;

    for (int i = 0; i < 64; i++) {
        sample = readincr(in);

        for (int j = TAPS - 1; j > 0; j--) {
            delay_line[j] = delay_line[j - 1];
        }
        delay_line[0] = sample;

        int32 accum = 0;
        for (int j = 0; j < TAPS; j++) {
            accum += (int32)delay_line[j] * (int32)coeffs[j];
        }

        int16 result = (int16)(accum >> 8);
        writeincr(out, result);
    }
}

