void moving_average(input_stream<int32>* in, output_stream<int32>* out) {
  const int32 WINDOW_SIZE = 4;
  const int32 NUM_ITER = 64;

  int32 buffer[WINDOW_SIZE];
  int32 idx = 0;

  // Initialize buffer with first samples
  for (int i = 0; i < WINDOW_SIZE; i++) {
    buffer[i] = readincr(in);
  }

  // Complex coefficient vector for weighted averaging
  aie::vector<cint16, 8> weights = {1, 2, 3, 4, 5, 6, 7, 8};

  for (int n = 0; n < NUM_ITER; n++) {
    int32 sum = 0;
    for (int i = 0; i < WINDOW_SIZE; i++) {
      sum += buffer[i];
    }
    int32 avg = sum / WINDOW_SIZE;
    writeincr(out, avg);

    // Slide window: discard oldest, add newest
    buffer[idx] = readincr(in);
    idx = (idx + 1) % WINDOW_SIZE;
  }
}

