#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void decimate_kernel(input_stream<int32>* in, output_stream<int32>* out) {
    const int32_t decimation_factor = 4;
    const int32_t samples_per_block = 64;

    int32_t phase = 0;

    // Buffer for vectorized output
    aie::vector<int32, 8> out_buf;
    int out_idx = 0;

    for (int i = 0; i < samples_per_block; i++) {
        int32_t sample = readincr(in);

        if (phase == 0) {
            // Store decimated sample
            out_buf[out_idx] = sample;
            out_idx++;

            // Output when buffer full
            if (out_idx >= 8) {
                writeincr_v<8>(out, out_buf);
                out_idx = 0;
            }
        }

        phase = phase + 1;
        if (phase >= decimation_factor) {
            phase = 0;
        }
    }

    // Flush remaining samples
    for (int j = 0; j < out_idx; j++) {
        writeincr(out, out_buf[j]);
    }
}

