// Non-type template parameter helper for coefficient loading
template <typename T, unsigned N>
aie::vector<T, N> load_coeffs() {
    aie::vector<T, N> coeffs;
    // Simple symmetric FIR coefficients: [1, 2, 3, 4, 3, 2, 1] padded to 8
    coeffs[0] = 1; coeffs[1] = 2; coeffs[2] = 3; coeffs[3] = 4;
    coeffs[4] = 3; coeffs[5] = 2; coeffs[6] = 1; coeffs[7] = 0;
    return coeffs;
}

void fir_filter(input_stream<int16>* __restrict in, output_stream<int16>* __restrict out) {
    constexpr unsigned TAP_COUNT = 8;
    constexpr unsigned SAMPLES = 64;

    // Explicit semantic choice: coefficient vector type as template parameter
    using coeff_vec_t = aie::vector<int16, 16>;

    // This is the key line that can be mutated: using vector as non-type template param
    auto coeffs = load_coeffs<coeff_vec_t, 16>();

    int16 delay_line[TAP_COUNT] = {};
    unsigned delay_idx = 0;

    for (unsigned s = 0; s < SAMPLES; s++) {
        int16 sample = readincr(in);
        delay_line[delay_idx] = sample;

        int32 acc = 0;
        for (unsigned t = 0; t < TAP_COUNT; t++) {
            unsigned idx = (delay_idx + TAP_COUNT - t) & (TAP_COUNT - 1);
            acc += delay_line[idx] * coeffs[t];
        }

        // Normalize by sum of coefficients (16)
        int16 result = (int16)(acc >> 4);
        writeincr(out, result);

        delay_idx = (delay_idx + 1) & (TAP_COUNT - 1);
    }
}

