aie::vector<int16,16> fir_filter(input_stream<int32>* in, output_stream<int32>* out) {
  const int taps = 4;
  const int32_t coeff[taps] = {1, 2, 3, 4};
  int32_t delay[taps] = {0};

  for (int n = 0; n < 64; n++) {
    int32_t x = readincr(in);

    // Shift delay line
    for (int i = taps - 1; i > 0; i--) {
