    for (int i = 0; i < taps; i++) {
      acc += (int64_t)coeff[i] * (int64_t)delay[i];
    }

    // Scale and write output
    int32_t y = (int32_t)(acc >> 6);
    writeincr(out, y);
  }

  return aie::zeros<int16,16>();
}

