constexpr unsigned TAP_COUNT = 16;
constexpr unsigned NUM_SAMPLES = 128;

// Helper that takes vector size as non-type template parameter
template <aie::vector<int16, 16> N>
void apply_gain(aie::vector<uint16, 16>& vec, uint16 gain) {
  for (unsigned i = 0; i < 16; i++) {
    vec[i] = (vec[i] * gain) >> 8;
  }
}

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
  // Coefficients in Q8.8 format
  const uint16 coeffs[TAP_COUNT] = {
    16, 32, 48, 64, 80, 96, 112, 128,
    128, 112, 96, 80, 64, 48, 32, 16
  };

  uint16 delay_line[TAP_COUNT] = {0};
  unsigned tap_idx = 0;

  for (unsigned s = 0; s < NUM_SAMPLES; s++) {
    uint16 sample = readincr(in);

    delay_line[tap_idx] = sample;
    tap_idx = (tap_idx + 1) & (TAP_COUNT - 1);

    uint32 acc = 0;
    for (unsigned i = 0; i < TAP_COUNT; i++) {
      unsigned idx = (tap_idx + i) & (TAP_COUNT - 1);
      acc += (uint32)delay_line[idx] * coeffs[i];
    }

    uint16 result = (uint16)(acc >> 8);
    writeincr(out, result);
  }
}

