void prefix_scan(input_stream<int16>* in, output_stream<int32>* out) {
    const int samples = 64;
    const int lanes = 16;
    const int blocks = samples / lanes;
    const int16 reset_threshold = 1000;

    int32 running_sum = 0;
    aie::vector<int16, lanes> vec;
