#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_kernel(input_stream<int32>* in, output_stream<int32>* out) {
    const int TAP_COUNT = 16;
    const int NUM_SAMPLES = 32;

    // FIR coefficients (simple lowpass, sum to unity)
    const int32_t coeffs[TAP_COUNT] = {
        1, 2, 3, 4, 5, 6, 7, 8,
        8, 7, 6, 5, 4, 3, 2, 1
    };
    const int32_t scale_shift = 8; // divide by 256

    // Delay line - volatile qualifier causes missing operator overloads
    volatile aie::vector<int16, 16> delay_line = aie::broadcast<int16, 16>(0);

    for (int s = 0; s < NUM_SAMPLES; s++) {
        int32_t sample = readincr(in);

        // Shift delay line: new sample at position 0
        delay_line = aie::shuffle_down(delay_line, 1);
        delay_line[0] = sample;

        // Compute FIR output using vector MAC
        aie::vector<int16, 16> coeff_vec = aie::load_v<16>(coeffs);

        // Element-wise multiply and accumulate
        int64_t acc = 0;
        for (int t = 0; t < TAP_COUNT; t++) {
            acc += (int64_t)delay_line[t] * (int64_t)coeff_vec[t];
        }

        // Apply scaling and saturate
        int32_t result = (int32_t)(acc >> scale_shift);
        writeincr(out, result);
    }
}

