#include <aie_api/aie_adf.hpp>

void fir_filter_int32(input_stream<int32>* in, output_stream<int32>* out) {
    // 4-tap FIR coefficients: moving average filter
    const int16 coeff[4] = {16384, 16384, 16384, 16384};
    const int shift = 16;

    // Delay line state as int16 vectors
    aie::vector<int16, 8> delay0 = aie::zeros<int16, 8>();
    aie::vector<int16, 8> delay1 = aie::zeros<int16, 8>();
    aie::vector<int16, 8> delay2 = aie::zeros<int16, 8>();
    aie::vector<int16, 8> delay3 = aie::zeros<int16, 8>();

    aie::vector<int16, 8> coeff_vec = aie::load_v<8>((int16*)coeff);

    // Process 16 iterations of 8 samples each
    for (int n = 0; n < 16; n++) {
        // Read 8 int32 samples, convert to int16
        aie::vector<int32, 8> in_vec;
        for (int i = 0; i < 8; i++) {
            in_vec[i] = readincr(in);
        }

        // Shift delay line
        delay3 = delay2;
        delay2 = delay1;
        delay1 = delay0;
        delay0 = in_vec.cast_to<int16>();

        // Complex accumulator for real MAC - type mismatch
        aie::accum<cacc48, 8> acc = aie::zeros<cacc48, 8>();

        // MAC operations with complex accumulator on real vectors
        acc = aie::mac(acc, delay0, coeff_vec);
        acc = aie::mac(acc, delay1, coeff_vec);
        acc = aie::mac(acc, delay2, coeff_vec);
        acc = aie::mac(acc, delay3, coeff_vec);

        // Convert back to int32 and write
        aie::vector<int16, 8> result16 = acc.to_vector<int16>(shift);
        aie::vector<int32, 8> result32 = result16.unpack();

        for (int i = 0; i < 8; i++) {
            writeincr(out, result32[i]);
        }
    }
}

