#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    // 4-tap FIR, process 64 samples
    const uint16 coeffs[4] = {1, 2, 3, 4};
    uint16 shift_reg[4] = {0, 0, 0, 0};

    for (int n = 0; n < 64; n++) {
        // Shift delay line
        shift_reg[3] = shift_reg[2];
        shift_reg[2] = shift_reg[1];
        shift_reg[1] = shift_reg[0];
        shift_reg[0] = readincr(in);

        // Compute MAC with acc80 accumulator
        aie::accum<acc80, 8> acc = aie::zeros<acc48, 8>();

        // Scalar accumulation (broadcast to vector lanes)
        int32_t sum = 0;
        for (int i = 0; i < 4; i++) {
            sum += (int32_t)coeffs[i] * (int32_t)shift_reg[i];
        }

        // Saturate and output
        uint16 result = (sum > 65535) ? 65535 : ((sum < 0) ? 0 : (uint16)sum);
        writeincr(out, result);
    }
}

