#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<int32>* in, output_stream<int32>* out) {
  const int32 coeffs[4] = {1, 2, 3, 4};
  int32 delay[4] = {0, 0, 0, 0};
  int32 phase = 0;

  for (int n = 0; n < 32; n++) {
    int32 sample = readincr(in);
    delay[phase] = sample;

    aie::accum<acc80, 4> acc = aie::zeros<acc80, 4>();
    for (int k = 0; k < 4; k++) {
      int idx = (phase + 4 - k) & 3;
      aie::vector<int32, 4> v = aie::broadcast<int32, 4>(delay[idx]);
      aie::vector<int32, 4> c = aie::broadcast<int32, 4>(coeffs[k]);
      acc = aie::mac(acc, v, c);
    }

    aie::vector<int32, 4> result = aie::srs(acc.to_vector<int32>(0), 0);
    int32 sum = result[0] + result[1] + result[2] + result[3];
    writeincr(out, sum);

    phase = (phase + 1) & 3;
  }
}

