// 4-tap symmetric FIR coefficients: designed for DC gain = 1.0
// Coeffs: c0, c1, c1, c0 with c0=0.15, c1=0.35 in Q15 fixed point
// Using int32 data, coefficients stored as int32 scaled by 2^15
const int32_t C0 = 4915;   // 0.15 * 32768
const int32_t C1 = 11469;  // 0.35 * 32768
const int32_t SHIFT = 15;  // Q15 normalization

void fir_filter(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    // Delay line state - must persist across loop iterations
    static int32_t d0 = 0;
    static int32_t d1 = 0;
    static int32_t d2 = 0;
    static int32_t d3 = 0;

    // Coefficients loaded into vectors for MAC operations
    // Vector lanes: [c0, c1, c1, c0] for symmetric FIR
    const int32_t coeffs[4] = {C0, C1, C1, C0};
    aie::vector<int32_t, 4> cvec = aie::load_v<4>(coeffs);

    // Process 32 samples per invocation
    for (int n = 0; n < 32; n++) {
        // Read new sample and shift delay line
        d3 = d2;
        d2 = d1;
        d1 = d0;
        d0 = readincr(in);

        // Load delay line into vector: [d0, d1, d2, d3]
        // For symmetric FIR: fold to [d0+d3, d1+d2, d1+d2, d0+d3] then * [c0,c1,c1,c0]
        // Or: load as-is and use direct MAC with coefficient vector
        int32_t data[4] = {d0, d1, d2, d3};
        aie::vector<int32_t, 4> dvec = aie::load_v<4>(data);

        // MAC: accumulator = sum of products
        // Using aie::mul then reduce, or aie::mac with explicit accumulator
        aie::accum<acc80, 4> acc = aie::zeros<acc80, 4>();
        acc = aie::mac(acc, dvec, coeffs);

        // Extract sum from all lanes and normalize
        // Simple approach: convert to vector and sum manually
        aie::vector<int32_t, 4> prod = acc.to_vector<int32_t>(SHIFT);

        // Final sum of all partial products
        int32_t result = prod[0] + prod[1] + prod[2] + prod[3];

        // Saturate and write
        int32_t saturated = result;
        if (result > 2147483647) saturated = 2147483647;
        if (result < -2147483648) saturated = -2147483648;

        writeincr(out, saturated);
    }
}

