void moving_avg(input_stream<int32_t>* in, output_stream<int32_t>* out) {
  const int32_t WINDOW_SIZE = 4;
  int32_t delay_line[4] = {0, 0, 0, 0};
  int32_t phase = 0;

  aie::vector<int32_t, 4> coeff = aie::broadcast<int32_t, 4>(1);

  for (int i = 0; i < 64; i++) {
    int32_t sample = readincr(in);

    delay_line[phase] = sample;

    aie::vector<int32_t, 4> data = aie::load_v<4>(delay_line);

    aie::vector<int32_t, 4> prod = aie::mul(data, coeff);

    int32_t sum = 0;
    for (int j = 0; j < WINDOW_SIZE; j++) {
      sum += delay_line[j];
    }
    int32_t result = sum / WINDOW_SIZE;

    writeincr(out, result);

    phase++;
    if (phase >= WINDOW_SIZE) phase = 0;
  }
}

