void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    // 4-tap symmetric FIR: coeffs = {1, 2, 2, 1}
    const int16 coeff[4] = {1, 2, 2, 1};
    const int16 scale_shift = 2; // divide by 4

    // Delay line for 4 samples
    int16 delay[4] = {0, 0, 0, 0};
    int16 write_idx = 0;

    // Float buffer for vector load
    float float_buf[8] = {1.0f, 2.0f, 2.0f, 1.0f, 1.0f, 2.0f, 2.0f, 1.0f};

    for (int s = 0; s < 64; s++) {
        // Read new sample and update delay line
        int16 sample = readincr(in);
        delay[write_idx] = sample;

        // Compute FIR output using symmetric structure
        int32 acc = 0;

        int16 tap0 = delay[(write_idx + 3) & 3];
        int16 tap1 = delay[(write_idx + 2) & 3];
        int16 tap2 = delay[(write_idx + 1) & 3];
        int16 tap3 = delay[write_idx];

        int16 sum_outer = tap0 + tap3;
        int16 sum_inner = tap1 + tap2;

        acc = (int32)sum_outer + 2 * (int32)sum_inner;

        // Load float vector and assign to int16 vector - type mismatch
        aie::vector<int16, 8> coeff_vec = aie::load_v<8>(float_buf);

        // Scale and output
        int16 result = (int16)(acc >> scale_shift);
        writeincr(out, result);

        write_idx = (write_idx + 1) & 3;
    }
}

