// Helper: accumulate FIR tap using AIE accumulator
void accumulate_tap(aie::accum<acc48, 4> acc, int16_t sample, int16_t coeff) {
    aie::vector<int16_t, 4> s = aie::broadcast<int16_t, 4>(sample);
    aie::vector<int16_t, 4> c = aie::broadcast<int16_t, 4>(coeff);
    acc = aie::mac(acc, s, c);
}

void decimate_kernel(input_stream<int32>* in, output_stream<int32>* out) {
    for (int i = 0; i < 32; i++) {
        aie::accum<acc48, 4> acc = aie::zeros<acc48, 4>();

        for (int dec = 0; dec < DECIMATION_FACTOR; dec++) {
            int32_t x32 = readincr(in);
            int16_t x = (int16_t)(x32 & 0xFFFF);
            accumulate_tap(acc, x, COEFF[dec]);
        }

        aie::vector<int16_t, 4> result = acc.to_vector<int16_t>(2);
        writeincr(out, (int32_t)result[0]);
    }
}

