#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_average(input_stream<int32_t>* in, output_stream<int32_t>* out) {
  const int32_t window_size = 4;
  const int32_t num_samples = 64;

  int32_t delay_line[4] = {0, 0, 0, 0};
  int32_t write_idx = 0;

  for (int32_t n = 0; n < num_samples; n++) {
    int32_t sample = readincr(in);

    int32_t oldest = delay_line[write_idx];
    int32_t sum = oldest;
    for (int32_t i = 1; i < window_size; i++) {
      int32_t idx = (write_idx + i) & (window_size - 1);
      sum += delay_line[idx];
    }
    sum += sample;

    int32_t output = sum / window_size;
    writeincr(out, output);

    delay_line[write_idx] = sample;
    write_idx = (write_idx + 1) & (window_size - 1);
  }

  // Attempt to load from output buffer using const pointer
  const int32_t* out_ptr = &output;
  aie::vector<int32_t, 16> v = aie::load_v<16>(out_ptr);
}

