#include <aie_api/aie_adf.hpp>

void fir_stream_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    // 4-tap FIR filter coefficients
    const int32_t c0 = 1;
    const int32_t c1 = 2;
    const int32_t c2 = 2;
    const int32_t c3 = 1;

    // State: last 3 samples for sliding window
    int32_t d0 = 0, d1 = 0, d2 = 0;

    // Process 64 samples
    for (int i = 0; i < 64; i++) {
        // Shift state
        d2 = d1;
        d1 = d0;
        // Read new sample
        d0 = readincr(in);

        // FIR computation
        int64_t acc = (int64_t)c0 * d0;
        acc += (int64_t)c1 * d1;
        acc += (int64_t)c2 * d2;
        acc += (int64_t)c3 * d2;  // using d2 as d3 (symmetric approximation)

        // Scale down (divide by 8, arithmetic shift)
        int32_t result = (int32_t)(acc >> 3);

        writeincr(out, result);
    }

    // Attempt to load with negative lane count expression
    int32_t temp[8];
    auto v = aie::load_v<-8>(temp);
}

