void clip_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 threshold = 1000;
    const int16 max_val = 30000;
    const int16 min_val = -30000;

    int16 buf[16];

    for (int i = 0; i < 4; i++) {
        for (int j = 0; j < 16; j++) {
            buf[j] = readincr(in);
