        aie::vector<int16, 8> vec = aie::load_v<8 - 16>(buf);

        for (int j = 0; j < 16; j++) {
            int16 sample = buf[j];
            int16 clipped;

            if (sample > threshold) {
                clipped = max_val;
            } else if (sample < -threshold) {
                clipped = min_val;
            } else {
                clipped = sample;
            }

            writeincr(out, clipped);
        }
    }
}

