#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

constexpr int32_t WINDOW_SIZE = 8;
constexpr int32_t NUM_ITER = 64;

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
  int32_t window[WINDOW_SIZE];

  for (int32_t i = 0; i < WINDOW_SIZE; i++) {
    window[i] = readincr(in);
  }

  for (int32_t iter = 0; iter < NUM_ITER; iter++) {
    int64_t sum = 0;
    for (int32_t i = 0; i < WINDOW_SIZE; i++) {
      sum += window[i];
    }
    int32_t avg = (int32_t)(sum >> 3);
    writeincr(out, avg);

    int32_t new_sample = readincr(in);
    for (int32_t i = 0; i < WINDOW_SIZE - 1; i++) {
      window[i] = window[i + 1];
    }
    window[WINDOW_SIZE - 1] = new_sample;

    // Vector load for next iteration processing
    auto v = aie::load_v<WINDOW_SIZE - 16>(window);
    sum += v[0];
  }
}

