void fir_filter(input_stream<uint16>* restrict in, output_stream<uint16>* restrict out) {
    const uint16_t taps[8] = {1, 2, 3, 4, 5, 6, 7, 8};
    const int num_taps = 8;
    const int lanes = 8;
    const int samples_per_iter = 8;
    const int total_samples = 256;

    uint16_t delay_line[num_taps] = {0};

    for (int s = 0; s < total_samples; s += samples_per_iter) {
        uint16_t new_samples[samples_per_iter];
        for (int i = 0; i < samples_per_iter; i++) {
            new_samples[i] = readincr(in);
        }

        for (int i = 0; i < samples_per_iter; i++) {
            for (int j = num_taps - 1; j > 0; j--) {
                delay_line[j] = delay_line[j - 1];
            }
            delay_line[0] = new_samples[i];

            aie::vector<uint16_t, 8> tap_vec = aie::load_v<lanes - 16>(taps);
            aie::vector<uint16_t, 8> delay_vec = aie::load_v<lanes - 16>(delay_line);

            aie::accum<acc48, 8> acc = aie::mul(tap_vec, delay_vec);
            uint16_t result = acc.to_vector<uint16_t>(4)[0];
            writeincr(out, result);
        }
    }
}

