void fir_filter(input_stream<int16>* in, output_stream<int16>* out) {
    const int TAPS = 4;
    int16 coeffs[TAPS] = {1, 2, 3, 4};
    const int16 delay[TAPS] = {0, 0, 0, 0};

    for (int n = 0; n < 64; n++) {
        aie::vector<int16, 4> vec;
        int32 acc = 0;

        for (int i = TAPS - 1; i > 0; i--) {
