        for (int i = 0; i < TAPS; i++) {
            acc += (int32)delay[i] * (int32)coeffs[i];
        }

        int16 shift_amount = 3;
        int16 result = (int16)(acc >> shift_amount);
        writeincr(out, result);
    }
}

