void fir_filter(input_buffer<int32>& in, output_buffer<int32>& out) {
    // 4-tap FIR with coefficients that sum to power-of-two for clean scaling
    const int32_t c0 = 1;
    const int32_t c1 = 2;
    const int32_t c2 = 2;
    const int32_t c3 = 1;
