void moving_avg_kernel(input_buffer<int16>& in, output_buffer<int16>& out) {
    const int16 TAP_COUNT = 4;
    const int16 VEC_SIZE = 16;
    const int16 SAMPLES = 64;

    auto in_iter = aie::begin(in);
    auto out_iter = aie::begin(out);

    for (int i = 0; i < SAMPLES / VEC_SIZE; i++) {
