#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter_uint16(input_buffer<cint16>& in, output_buffer<cint16>& out) {
    const int NUM_TAPS = 4;
    const int NUM_SAMPLES = 32;

    const int16_t coeff[NUM_TAPS] = {1, 1, 1, 1};

    cint16 delay_line[NUM_TAPS] = {{0, 0}, {0, 0}, {0, 0}, {0, 0}};

    auto in_iter = aie::begin(in);
    auto out_iter = aie::begin(out);

    for (int n = 0; n < NUM_SAMPLES; n++) {
        cint16 sample = *in_iter++;

        for (int i = NUM_TAPS - 1; i > 0; i--) {
            delay_line[i] = delay_line[i - 1];
        }
        delay_line[0] = sample;

        int64_t acc_real = 0;
        int64_t acc_imag = 0;
        for (int i = 0; i < NUM_TAPS; i++) {
            acc_real += (int64_t)delay_line[i].real * coeff[i];
            acc_imag += (int64_t)delay_line[i].imag * coeff[i];
        }

        const int SHIFT_BITS = 2;
        int16_t out_real = (int16_t)(acc_real >> SHIFT_BITS);
        int16_t out_imag = (int16_t)(acc_imag >> SHIFT_BITS);

