    for (int32_t i = 0; i < window_size - 1; i++) {
      buffer[i] = buffer[i + 1];
    }
    buffer[window_size - 1] = next;
  }

  aie::vector<int32_t, 8> temp = aie::broadcast<int32_t, 8>(0);
  aie::store_v<4>(buffer, temp);
}

