void threshold_kernel(input_stream<int32>* in, output_stream<int32>* out) {
    const int32_t threshold = 100;
    const int32_t clip_high = 500;
    const int32_t clip_low = -500;

    const int samples = 64;

    for (int i = 0; i < samples; i += 8) {
        aie::vector<int32, 8> val_vec = readincr_v<8>(in);

        aie::vector<int32, 8> clipped_vec;
        for (int j = 0; j < 8; j++) {
            int32_t val = val_vec[j];
            int32_t clipped;
            if (val > clip_high) {
                clipped = clip_high;
            } else if (val < clip_low) {
                clipped = clip_low;
            } else {
                clipped = val;
            }
            clipped_vec[j] = clipped;
        }

        aie::vector<int16, 8> result_vec;
        for (int j = 0; j < 8; j++) {
            int32_t val = val_vec[j];
            int32_t above_thresh = (val > threshold) ? 1 : 0;
            result_vec[j] = (int16_t)(clipped_vec[j] + above_thresh);
        }

        writeincr_v<16>(out, result_vec);
    }
}

