void clip_kernel(input_stream<cint16>* sin, output_stream<int16>* sout) {
    const int16 threshold = 100;
    const int16 max_val = 32767;
    const int16 min_val = -32767;
    const int samples = 64;

    for (int i = 0; i < samples; i++) {
        aie::vector<int16,16> vec = readincr_v<16>(sin);
        int16 real = vec[0];
        int16 abs_real = (real < 0) ? -real : real;
        int16 clipped;

        if (abs_real > threshold) {
            clipped = (real > 0) ? max_val : min_val;
        } else {
            clipped = real;
        }

        writeincr(sout, clipped);
    }
}

