#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_kernel(input_stream<cint16>* in, output_stream<cint16>* out) {
    const int TAP_COUNT = 4;
    const int SAMPLES = 128;

    // Coefficients for complex FIR (int16 real, int16 imag)
    cint16 coeffs[TAP_COUNT];
    coeffs[0] = {3277, 0};    // 0.1 in Q15
    coeffs[1] = {6554, 0};    // 0.2 in Q15
    coeffs[2] = {6554, 0};    // 0.2 in Q15
    coeffs[3] = {3277, 0};    // 0.1 in Q15

    // Delay line for complex samples
    cint16 delay_line[TAP_COUNT] = {{0,0}, {0,0}, {0,0}, {0,0}};

    for (int s = 0; s < SAMPLES; ++s) {
        // Shift delay line
        for (int t = TAP_COUNT - 1; t > 0; --t) {
            delay_line[t] = delay_line[t-1];
        }

        // Read new complex sample - vectorized read
        aie::vector<int16,16> sample_vec = readincr_v<16>(in);
        cint16 sample = {sample_vec[0], sample_vec[1]};
        delay_line[0] = sample;

        // Compute complex FIR: sum of products
        int32 acc_real = 0;
        int32 acc_imag = 0;

        for (int t = 0; t < TAP_COUNT; ++t) {
            // (a+ib)(c+id) = (ac-bd) + i(ad+bc)
            int32 real_prod = (int32)delay_line[t].real * coeffs[t].real - 
                              (int32)delay_line[t].imag * coeffs[t].imag;
            int32 imag_prod = (int32)delay_line[t].real * coeffs[t].imag + 
                              (int32)delay_line[t].imag * coeffs[t].real;
            acc_real += real_prod;
            acc_imag += imag_prod;
        }

        // Scale and saturate to int16
        const int SHIFT = 15;
        int16 out_real = (int16)(acc_real >> SHIFT);
        int16 out_imag = (int16)(acc_imag >> SHIFT);

        cint16 result = {out_real, out_imag};
        writeincr(out, result);
    }
}

