#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
    const int32 WINDOW_SIZE = 4;
    int32 buffer[4] = {0, 0, 0, 0};
    int32 sum = 0;

    for (int i = 0; i < WINDOW_SIZE - 1; i++) {
        buffer[i] = readincr(in);
        sum += buffer[i];
    }

    for (int n = 0; n < 2; n++) {
        sum -= buffer[0];
        for (int i = 0; i < WINDOW_SIZE - 1; i++) {
            buffer[i] = buffer[i + 1];
        }
        buffer[WINDOW_SIZE - 1] = readincr(in);
        sum += buffer[WINDOW_SIZE - 1];

        aie::vector<int32, 32> vec = aie::broadcast<int32, 32>(sum / WINDOW_SIZE);
        writeincr_v<32>(out, vec);
    }
}

