// FILE: kernels/fir_int32.cc
#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

// 4-tap FIR with int32 coefficients
const int32_t COEFFS[4] = {1, -2, 3, -4};
const int TAP_COUNT = 4;
const int SAMPLES = 64;

void fir_int32_stream(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    // Delay line for FIR state
    int32_t delay[TAP_COUNT] = {0, 0, 0, 0};
    int32_t sample;

    for (int n = 0; n < SAMPLES; n += 32) {
        // Read 32 samples as vector
        aie::vector<int32_t, 32> vin = readincr_v<32>(in);

        // Shift delay line with new sample
        for (int t = TAP_COUNT - 1; t > 0; t--) {
            delay[t] = delay[t - 1];
        }
        delay[0] = vin[0];

        // Compute FIR output for first sample only
        int64_t acc = 0;
        for (int t = 0; t < TAP_COUNT; t++) {
            acc += (int64_t)delay[t] * (int64_t)COEFFS[t];
        }

        // Saturate to int32 range
        int32_t out_val;
        if (acc > INT32_MAX) out_val = INT32_MAX;
        else if (acc < INT32_MIN) out_val = INT32_MIN;
        else out_val = (int32_t)acc;

        // Broadcast to vector and write
        aie::vector<int32_t, 32> vout = aie::broadcast<int32_t, 32>(out_val);
        writeincr_v<32>(out, vout);
    }
}

