void threshold_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 threshold = 1000;
    const int16 clamp_low = -2048;
    const int16 clamp_high = 2047;
    const int samples_per_block = 128;
    for (int blk = 0; blk < samples_per_block / vector_lanes; blk++) {
        aie::vector<int16, vector_lanes> vin = readincr_v<vector_lanes>(in);
        for (int i = 0; i < vector_lanes; i++) {
