            int16 out_val;
            if (val > threshold) {
                out_val = clamp_high;
            } else if (val < -threshold) {
                out_val = clamp_low;
            } else {
                out_val = val;
            }
            writeincr(out, out_val);
        }
    }
    constexpr int vector_lanes = 16;
}

