// Decimation factor: keep 1 out of every DECIM samples
constexpr int DECIM = 4;
constexpr int BLOCK_SAMPLES = 256;

void decimate_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
  // Process blocks of input, keeping every DECIM-th sample
  for (int b = 0; b < BLOCK_SAMPLES / (VECTOR_LANES * DECIM); b++) {
    // Read vector of samples
    aie::vector<int32_t, VECTOR_LANES> vec = readincr_v<VECTOR_LANES>(in);

    // Phase selection: extract every DECIM-th element starting at phase 0
    // For DECIM=4 and VECTOR_LANES=8, we select indices 0,4 from each half
    for (int i = 0; i < VECTOR_LANES / DECIM; i++) {
      int phase = 0;
      int src_idx = i * DECIM + phase;
      int32_t sample = vec[src_idx];
      writeincr(out, sample);
    }

    // Skip remaining samples in this decimation group (read and discard)
    for (int skip = 1; skip < DECIM; skip++) {
      aie::vector<int32_t, VECTOR_LANES> discard = readincr_v<VECTOR_LANES>(in);
    }
  }
}

