#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

// 4-tap FIR with scalar writeincr for single sample output
void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
  // Coefficients for low-pass filter
  const uint16 c0 = 21845; // 1/3 in Q16
  const uint16 c1 = 21845;
  const uint16 c2 = 10922; // 1/6 in Q16
  const uint16 c3 = 10922;

  // Delay line state
  uint16 d0 = 0;
  uint16 d1 = 0;
  uint16 d2 = 0;
  uint16 d3 = 0;

  // Process 64 samples
  const int samples = 64;

  for (int i = 0; i < samples; i++) {
    // Shift delay line
    d3 = d2;
    d2 = d1;
    d1 = d0;
    d0 = readincr(in);

    // Compute output: scalar MAC with uint32 accumulation
    uint32 acc = 0;
    acc += (uint32)d0 * c0;
    acc += (uint32)d1 * c1;
    acc += (uint32)d2 * c2;
    acc += (uint32)d3 * c3;

    // Normalize: right-shift by 16 for Q16 coefficients
    uint16 out_val = (uint16)(acc >> 16);

    // Scalar write for single sample
    writeincr_v<1>(out, out_val);
  }
}

