    const int32_t threshold = 100;
    const int32_t clip_high = 255;
    const int32_t clip_low = 0;

    for (int i = 0; i < 8; i++) {
        aie::vector<int32_t, VEC_SIZE> vec = readincr_v<VEC_SIZE>(in);
