// FILE: kernels/fir_filter.cc
#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

// 4-tap FIR coefficients (Q15 normalized)
const int16 COEFFS[4] = {16384, 10923, 5461, 2731};

void fir_filter(input_buffer<cint16>* in, output_buffer<cint16>* out) {
    // State buffer for delay line
    cint16 delay[4] = {{0, 0}, {0, 0}, {0, 0}, {0, 0}};

    const int SAMPLES = 64;

    for (int n = 0; n < SAMPLES; n++) {
        cint16 sample = readincr(in);

        // Shift delay line
        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];
        delay[0] = sample;

        // MAC computation using 64-bit accumulator for headroom
        int64 acc_r = 0;
        int64 acc_i = 0;

        for (int t = 0; t < 4; t++) {
            acc_r += (int64)delay[t].real * COEFFS[t];
            acc_i += (int64)delay[t].imag * COEFFS[t];
        }

        // Scale by 2 (coeffs sum to ~0.5 in Q15, need gain of 2)
        int32 out_r = (int32)(acc_r >> 14);
        int32 out_i = (int32)(acc_i >> 14);

        // Saturate to int16 range
        cint16 result;
        result.real = (int16)(out_r > 32767 ? 32767 : (out_r < -32768 ? -32768 : out_r));
        result.imag = (int16)(out_i > 32767 ? 32767 : (out_i < -32768 ? -32768 : out_i));

        writeincr(out, result);
    }
}

