#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* sin, const output_buffer<int16>& bout) {
    const int TAPS = 4;
    const int SHIFT = 14;
    const int32_t COEFF[TAPS] = {16384, 8192, 4096, 2048};

    int32_t delay[TAPS] = {0, 0, 0, 0};

    for (int n = 0; n < 64; n++) {
        uint16 x = readincr(sin);

        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];
        delay[0] = x;

        int64_t acc = 0;
        for (int i = 0; i < TAPS; i++) {
            acc += (int64_t)COEFF[i] * (int64_t)delay[i];
        }

        int32_t y = (int32_t)(acc >> SHIFT);

        if (y > 65535) y = 65535;
        if (y < 0) y = 0;

        bout[n] = (int16)y;
