#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

// 4-tap symmetric FIR: coefficients for lowpass at ~0.25 normalized frequency
// Using named constants for mutation-friendly baseline
constexpr int16 COEF0 = 164;   // 0.125 * 512 * 2
constexpr int16 COEF1 = 495;   // 0.375 * 512 * 2
constexpr int NUM_TAPS = 4;
constexpr int NUM_OUTPUTS = 64;

void fir_filter(input_buffer<int16>&& in, output_stream<int16>* out) {
  // Delay line state - explicit named state for future mutation
  int16 delay[NUM_TAPS] = {0, 0, 0, 0};

  // Window-based input requires iterator access
  auto pIn = aie::begin(in);

  for (int n = 0; n < NUM_OUTPUTS; n++) {
    // Shift delay line
    delay[3] = delay[2];
    delay[2] = delay[1];
    delay[1] = delay[0];

    // Read new sample from window
    delay[0] = *pIn++;

    // Symmetric FIR: tap symmetry exploited
    // h[0]=h[3]=COEF0, h[1]=h[2]=COEF1
    int32 sum = 0;
    sum += (int32)COEF0 * ((int32)delay[0] + (int32)delay[3]);
    sum += (int32)COEF1 * ((int32)delay[1] + (int32)delay[2]);

    // Scale by 10 bits (512 * 2 = 1024 scaling)
    int16 result = (int16)(sum >> 10);

    writeincr(out, result);
  }
}

