void fir_filter(input_stream<uint16>* in, output_buffer<int16, adf::extents<256>>& out) {
    const int16 coeffs[4] = {1, 2, 2, 1};
    const int scale = 3;
    const int num_samples = 64;

    uint16 delay_line[4] = {0, 0, 0, 0};
    int delay_idx = 0;

    for (int n = 0; n < num_samples; n++) {
        uint16 sample = readincr(in);

        delay_line[delay_idx] = sample;

        int32 acc = 0;
        for (int k = 0; k < 4; k++) {
            int idx = (delay_idx + 1 + k) & 3;
            acc += (int32)delay_line[idx] * coeffs[k];
        }

        uint16 result = (uint16)(acc >> scale);
        writeincr(out, result);

        delay_idx = (delay_idx - 1) & 3;
    }
}

