// FILE: kernels/fir_filter.cc
#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* sin, output_buffer<int16>& outbuf) {
    const int16 taps[4] = {1, 2, 2, 1};
    const int16 scale = 2;
    int16 delay[4] = {0, 0, 0, 0};
    uint16 idx = 0;

    for (int n = 0; n < 64; n++) {
        uint16 sample = readincr(sin);
        delay[idx] = (int16)sample;

        aie::accum<acc48, 4> acc = aie::zeros<acc48, 4>();
        for (int t = 0; t < 4; t++) {
            uint16 tap_idx = (idx + 4 - t) & 3;
            aie::vector<int16, 4> d = aie::broadcast<int16, 4>(delay[tap_idx]);
            aie::vector<int16, 4> c = aie::broadcast<int16, 4>(taps[t]);
            acc = aie::mac(acc, d, c);
        }

        aie::vector<int16, 4> result = acc.to_vector<int16>(scale);
        aie::store_v(outbuf, result);

        idx = (idx + 1) & 3;
    }
}

