void fir_filter(input_stream<int32>* in, output_buffer<int16>& out) {
    const int32_t coeffs[4] = {1, 2, 3, 4};
    const int32_t num_taps = 4;
    const int32_t num_samples = 64;

    int32_t delay_line[4] = {0, 0, 0, 0};
