#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<cint16>* in, output_stream<cint16>* out) {
  const int16 coeff[4] = {16384, 24576, 24576, 16384};
  const int shift = 15;
  const unsigned samples = 64;

  cint16 delay_line[8] = {};

  for (unsigned i = 0; i < samples; i++) {
    cint16 sample = readincr(in);

    int16* d_begin = aie::begin(delay_line);

    for (auto it = d_begin + 2; it != d_begin + 16; ++it) {
      *(it - 2) = *it;
    }

    delay_line[3] = sample;

    int64 acc_real = 0;
    int64 acc_imag = 0;

    for (unsigned t = 0; t < 4; t++) {
      acc_real += (int64)coeff[t] * (int64)delay_line[3 - t].real;
      acc_imag += (int64)coeff[t] * (int64)delay_line[3 - t].imag;
    }

    int32 out_real = (int32)(acc_real >> shift);
    int32 out_imag = (int32)(acc_imag >> shift);

    if (out_real > 32767) out_real = 32767;
    if (out_real < -32768) out_real = -32768;
    if (out_imag > 32767) out_imag = 32767;
    if (out_imag < -32768) out_imag = -32768;

    cint16 result;
    result.real = (int16)out_real;
    result.imag = (int16)out_imag;
    writeincr(out, result);
  }
}

