template<int ScaleFactor, int ShiftAmount>
struct ScaleShiftParams {
  using input_buffer_t = input_buffer<int16>;
  static constexpr int scale = ScaleFactor;
  static constexpr int shift = ShiftAmount;
};

void scale_shift_kernel(input_buffer<int16>& in, output_buffer<int16>& out) {
  using Params = ScaleShiftParams<3, 2>;
  Params::input_buffer_t::iterator it = aie::begin(in);
  Params::input_buffer_t::iterator end_it = aie::end(in);

  while (it != end_it) {
