#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_buffer<int16>& in, output_buffer<int16>& out) {
    const int16 coeffs[4] = {1, 2, 3, 4};
    const int taps = 4;
    const int samples = 64;

    int16 delay_line[4] = {0, 0, 0, 0};

    auto in_iter = aie::begin(in);
    auto out_iter = aie::begin(out);

    for (int n = 0; n < samples; n++) {
        int16 sample = *in_iter++;

        for (int i = taps - 1; i > 0; i--) {
            delay_line[i] = delay_line[i-1];
        }
        delay_line[0] = sample;

        int32 accum = 0;
        for (int i = 0; i < taps; i++) {
            accum += (int32)delay_line[i] * (int32)coeffs[i];
        }

        int16 result = (int16)(accum >> 3);

        writeincr(out, result);
    }
}

