#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
  const int32_t WINDOW_SIZE = 4;
  int32_t delay_line[4] = {0, 0, 0, 0};
  int32_t write_idx = 0;

  for (int i = 0; i < 64; i++) {
    int32_t sample = readincr(in);

    int32_t old_sample = delay_line[write_idx];
    delay_line[write_idx] = sample;

    int32_t sum = 0;
    for (int j = 0; j < WINDOW_SIZE; j++) {
      sum += delay_line[j];
    }
    int32_t avg = sum >> 2;

    aie::vector<int32_t, 8> out_vec = readincr_v<16>(in);
    writeincr(out, avg);

    write_idx++;
    if (write_idx >= WINDOW_SIZE) {
      write_idx = 0;
    }
  }
}

