#include <aie_api/aie_adf.hpp>

void moving_average(input_stream<int32>* in, output_stream<int32>* out) {
    const int32_t WINDOW_SIZE = 8;
    const int32_t NUM_SAMPLES = 64;

    int32_t delay_line[WINDOW_SIZE];
    for (int i = 0; i < WINDOW_SIZE; i++) {
        delay_line[i] = 0;
    }
    int32_t sum = 0;
    int32_t write_idx = 0;

    for (int n = 0; n < NUM_SAMPLES + WINDOW_SIZE - 1; n++) {
        int32_t sample = 0;
        if (n < NUM_SAMPLES) {
            sample = readincr(in, &sum);
        }

        sum = sum - delay_line[write_idx] + sample;
        delay_line[write_idx] = sample;
        write_idx = (write_idx + 1) % WINDOW_SIZE;

        if (n >= WINDOW_SIZE - 1) {
            int32_t avg = sum / WINDOW_SIZE;
            writeincr(out, avg);
        }
    }
}

