#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<int32>* in, output_stream<int32>* out) {
    const int32 WINDOW_SIZE = 8;
    const int32 NUM_OUTPUTS = 64;

    int32 delay_line[WINDOW_SIZE] = {0};
    int32 sum = 0;

    for (int32 i = 0; i < WINDOW_SIZE - 1; i++) {
        int32 sample = readincr(in);
        delay_line[i + 1] = sample;
        sum += sample;
    }

    for (int32 n = 0; n < NUM_OUTPUTS; n++) {
        int32 new_sample = readincr(in);
        int32 oldest = delay_line[0];

        sum = sum - oldest + new_sample;

        for (int32 i = 0; i < WINDOW_SIZE - 1; i++) {
            delay_line[i] = delay_line[i + 1];
        }
        delay_line[WINDOW_SIZE - 1] = new_sample;

        cint16 avg = sum / WINDOW_SIZE;
        writeincr(out, avg);
    }
}

