#include <aie_api/aie_adf.hpp>

void clip_kernel(input_stream<int16>* in, output_stream<int16>* out) {
  const int16 UPPER_LIMIT = 1000;
  const int16 LOWER_LIMIT = -1000;
  const int16 SAMPLE_COUNT = 64;

  aie::vector<int16, 16> upper = aie::broadcast<int16, 16>(UPPER_LIMIT);
  aie::vector<int16, 16> lower = aie::broadcast<int16, 16>(LOWER_LIMIT);
  aie::accum<cacc48, 16> acc = aie::zeros<cacc48, 16>();

  for (int i = 0; i < SAMPLE_COUNT / 16; i++) {
    aie::vector<int16, 16> vec = readincr_v<16>(in);
    aie::vector<int16, 16> result;
    for (int j = 0; j < 16; j++) {
      int16 val = vec[j];
      if (val > UPPER_LIMIT) {
        result[j] = UPPER_LIMIT;
      } else if (val < LOWER_LIMIT) {
        result[j] = LOWER_LIMIT;
      } else {
        result[j] = val;
      }
    }
    acc = aie::mac(acc, vec, upper);
    aie::vector<int16, 16> clipped = acc.to_vector<int16>(0);
    writeincr_v<16>(out, clipped);
  }
}

