void fir_filter(input_stream<cint16>* in, output_stream<cint16>* out) {
    const int32 NUM_TAPS = 4;
    const int32 NUM_OUTPUTS = 32;

    cint16 coeffs[NUM_TAPS] = {{1, 0}, {2, 0}, {3, 0}, {4, 0}};
    cint16 delay_line[NUM_TAPS] = {{0, 0}, {0, 0}, {0, 0}, {0, 0}};

    for (int32 n = 0; n < NUM_OUTPUTS; ++n) {
        cint16 sample = readincr(in);

        for (int32 i = NUM_TAPS - 1; i > 0; --i) {
            delay_line[i] = delay_line[i - 1];
        }
        delay_line[0] = sample;

        aie::accum<acc48, 1> acc = aie::zeros<acc48, 1>();
        for (int32 i = 0; i < NUM_TAPS; ++i) {
            aie::vector<cint16, 1> v_coeff = aie::broadcast<cint16, 1>(coeffs[i]);
            aie::vector<cint16, 1> v_data = aie::broadcast<cint16, 1>(delay_line[i]);
            acc = aie::mac(acc, v_coeff, v_data);
        }

        cint16 result = acc.to_vector<cint16>(8)[0];
        writeincr(out, result);
    }
}

