void scale_shift_kernel(input_stream<cint16>* in, output_stream<cint16>* out) {
    const int samples = 64;
    const cint16 scale = {2, 0};
    const cint16 shift = {10, 5};

    for (int i = 0; i < samples; i++) {
        cint16 x = readincr(in);

        aie::vector<cint16, 4> vx = aie::broadcast<cint16, 4>(x);
        aie::vector<cint16, 4> vscale = aie::broadcast<cint16, 4>(scale);
