#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void moving_avg(input_stream<cint16>* in, output_stream<cint16>* out) {
    const int16 WINDOW_LEN = 4;
    const int16 SHIFT = 2;

    cint16 window[4];
    int16 real_parts[4];
    int16 imag_parts[4];

    for (int16 i = 0; i < WINDOW_LEN; i++) {
        window[i] = readincr(in);
        real_parts[i] = real(window[i]);
        imag_parts[i] = imag(window[i]);
    }

    for (int16 n = 0; n < 60; n++) {
        int64 real_sum = 0;
        int64 imag_sum = 0;

        for (int16 i = 0; i < WINDOW_LEN; i++) {
            real_sum += real_parts[i];
            imag_sum += imag_parts[i];
        }

        int16 out_real = (int16)(real_sum >> SHIFT);
        int16 out_imag = (int16)(imag_sum >> SHIFT);

        cint16 result;
        result.real = out_real;
        result.imag = out_imag;
        writeincr(out, result);

        for (int16 i = 0; i < WINDOW_LEN - 1; i++) {
            real_parts[i] = real_parts[i + 1];
            imag_parts[i] = imag_parts[i + 1];
        }

        cint16 new_sample = readincr(in);
        real_parts[WINDOW_LEN - 1] = real(new_sample);
        imag_parts[WINDOW_LEN - 1] = imag(new_sample);
    }
}

