#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void clip_complex(input_stream<cint16>* in, output_stream<cint16>* out) {
    const int16 threshold = 1000;

    for (int i = 0; i < 64; i++) {
        cint16 val = readincr(in);

        int16 real_part = real(val);
        int16 imag_part = val.imag;

        int16 clipped_real = real_part;
        int16 clipped_imag = imag_part;

        if (real_part > threshold) clipped_real = threshold;
        else if (real_part < -threshold) clipped_real = -threshold;

        if (imag_part > threshold) clipped_imag = threshold;
        else if (imag_part < -threshold) clipped_imag = -threshold;

        cint16 out_val;
        out_val.real = clipped_real;
        out_val.imag = clipped_imag;

        writeincr(out, out_val);
    }
}

