void moving_avg(input_stream<int16>* __restrict in, output_stream<int32>* __restrict out) {
  const int16 coeffs[4] = {1, 1, 1, 1};
  const int32 num_taps = 4;
  const int32 num_samples = 64;

  int16 delay_line[4] = {0, 0, 0, 0};

  for (int n = 0; n < num_samples; n++) {
    int16 sample = readincr(in);

    delay_line[3] = delay_line[2];
    delay_line[2] = delay_line[1];
    delay_line[1] = delay_line[0];
    delay_line[0] = sample;

    // Load coefficients as cint16 vector for complex MAC
    aie::vector<cint16, 4> coeff_vec = aie::load_v<4>((cint16*)coeffs);
    aie::vector<int16, 4> delay_vec = aie::load_v<4>(delay_line);

    // Complex multiply-accumulate
    aie::accum<cacc48, 4> acc = aie::mul(coeff_vec, delay_vec);
    int32 sum = aie::srs(acc, 0)[0];

    writeincr(out, sum);
  }
}

