#include <aie_api/aie_adf.hpp>

// cint16 is already defined by AIE headers; use the standard fields
// cint16 = struct { int16 real; int16 imag; };

void fir_filter(input_stream<cint16>* in, output_stream<cint16>* out) {
  // 4-tap FIR with symmetric coefficients for low-pass
  const int16 coeff[4] = {1, 2, 2, 1};
  const int scale = 6;  // sum of coeffs = 6, for normalization

  // Delay line for real and imag parts separately
  int32 sr[4] = {0, 0, 0, 0};
  int32 si[4] = {0, 0, 0, 0};
  int idx = 0;

  for (int n = 0; n < 64; n++) {
    cint16 x = readincr(in);

    // Access cint16 fields: .real and .imag (standard AIE layout)
    sr[idx] = x.real;
    si[idx] = x.imag;

    int32 acc_r = 0;
    int32 acc_i = 0;
    for (int t = 0; t < 4; t++) {
      int tap_idx = (idx + 4 - t) & 3;
      acc_r += sr[tap_idx] * coeff[t];
      acc_i += si[tap_idx] * coeff[t];
    }

    cint16 y;
    y.re = (int16)(acc_r / scale);
    y.im = (int16)(acc_i / scale);
    writeincr(out, y);

    idx = (idx + 1) & 3;
  }
}

