#include <aie_api/aie_adf.hpp>

void decimate_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    // Decimation factor of 4: keep 1 of every 4 samples
    const int DECIMATION_FACTOR = 4;
    const int BLOCK_SIZE = 64;
    const int SAMPLES_PER_ITER = BLOCK_SIZE / DECIMATION_FACTOR;

    // Coefficients for a simple averaging filter (1/4, 1/4, 1/4, 1/4)
    // Scaled to int16: 8192 = 0.25 * 32768
    const int16 COEFF_0 = 8192;
    const int16 COEFF_1 = 8192;
    const int16 COEFF_2 = 8192;
    const int16 COEFF_3 = 8192;
    const int SHIFT = 15; // For fixed-point scaling

    for (int block = 0; block < SAMPLES_PER_ITER; block++) {
        // Read 4 samples to decimate
        int16 s0 = readincr(in);
        int16 s1 = readincr(in);
        int16 s2 = readincr(in);
        int16 s3 = readincr(in);

        // Apply filter with saturation mode for safety
        int32 acc = 0;
        acc += (int32)s0 * COEFF_0;
        acc += (int32)s1 * COEFF_1;
        acc += (int32)s2 * COEFF_2;
        acc += (int32)s3 * COEFF_3;

        // Saturating right shift with explicit mode
        int16 result;
        if (acc > (INT32_MAX >> SHIFT)) {
            result = INT16_MAX;
        } else if (acc < (INT32_MIN >> SHIFT)) {
            result = INT16_MIN;
        } else {
            result = (int16)(acc >> SHIFT);
        }

        // Use vector write with saturation mode enum
        aie::vector<int16, 1> v = aie::broadcast<int16, 1>(result);
        aie::store_v(out, v, aie::saturation_mode::satur);
    }
}

