void clip_threshold(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t threshold_pos = 1000;
    const int32_t threshold_neg = -1000;
    const int32_t samples = 64;

    for (int i = 0; i < samples; i++) {
        int32_t val = readincr(in);
        int32_t clipped;

