#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
    // FIR filter with 4 taps, using uint16 data
    // Coefficients: 1, 2, 3, 4 (sum to 10, will divide by 10 to normalize)
    const int NUM_TAPS = 4;
    const uint16_t coeff[NUM_TAPS] = {1, 2, 3, 4};
    const uint16_t norm_shift = 4; // divide by 16 (close to 10, power of 2 for shift)

    // Delay line state
    uint16_t delay[NUM_TAPS] = {0, 0, 0, 0};
    int tap_idx = 0;

    for (int n = 0; n < 64; n++) {
        uint16_t sample = readincr(in);

        // Insert new sample into delay line (circular buffer)
        delay[tap_idx] = sample;

        // Compute FIR sum: sum of coeff[k] * delay[(tap_idx - k) & 3]
        uint32_t acc = 0;
        for (int k = 0; k < NUM_TAPS; k++) {
            int idx = (tap_idx - k) & (NUM_TAPS - 1);
            acc += (uint32_t)coeff[k] * (uint32_t)delay[idx];
        }

        // Normalize with right shift (round by adding 0.5 before shift)
        acc += (1 << (norm_shift - 1));
        uint16_t result = aie::to_fixed<uint16_t>(acc, norm_shift);

        writeincr(out, result);

        // Advance circular buffer index
        tap_idx = (tap_idx + 1) & (NUM_TAPS - 1);
    }
}

