void moving_avg(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 WINDOW_SIZE = 4;
    const int16 SCALE_SHIFT = 2;

    int32_t sum = 0;
    int16 window[4];
    int16 idx = 0;
    int16 filled = 0;

    for (int i = 0; i < 64; i++) {
