void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
  const int TAPS = 4;
  const uint16 coeffs[TAPS] = {1, 2, 3, 4};
  uint16 delay_line[TAPS] = {0};

  chess_prepare_for_pipelining;
  for (int n = 0; n < 64; n++) {
    uint16 sample = readincr(in);

    chess_loop_range(4);
    for (int i = TAPS - 1; i > 0; i--) {
      delay_line[i] = delay_line[i - 1];
    }
    delay_line[0] = sample;

    uint32 acc = 0;
    for (int i = 0; i < TAPS; i++) {
      acc += (uint32)delay_line[i] * (uint32)coeffs[i];
    }

    uint16 result = (uint16)(acc >> 8);
    writeincr(out, result);
  }
}

