void moving_avg_kernel(input_stream<int16>* in, output_stream<int32>* out) {
    // 4-tap moving average filter
    const int TAP_COUNT = 4;
    const int LOOP_ITERATIONS = 64;
    const int SHIFT_RIGHT = 2;  // divide by 4 = shift right by 2

    // Filter state: delay line for 4 samples
    int16 delay_line[TAP_COUNT] = {0, 0, 0, 0};

    for (int iter = 0; iter < LOOP_ITERATIONS; iter++) 
    chess_loop_range(64)
