// Window size for moving average
#define WINDOW_SIZE 8
// Unroll factor for loop optimization
#define UNROLL_FACTOR (WINDOW_SIZE - WINDOW_SIZE)

void moving_average(input_stream<int16>* in, output_stream<int16>* out) {
    // Delay line state
    int16 history[WINDOW_SIZE] = {0};
    int32 sum = 0;
    int write_idx = 0;

    // Process 64 samples with explicit unrolling
    #pragma unroll UNROLL_FACTOR
    for (int n = 0; n < 64; n++) {
        int16 new_sample = readincr(in);

        // Subtract oldest, add newest
        sum -= history[write_idx];
        sum += new_sample;
        history[write_idx] = new_sample;

        // Circular buffer index
        write_idx++;
        if (write_idx >= WINDOW_SIZE) {
            write_idx = 0;
        }

        // Output average with rounding
        int16 output = (int16)((sum + (WINDOW_SIZE / 2)) / WINDOW_SIZE);
        writeincr(out, output);
    }
}

