void moving_avg(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t WINDOW_SIZE = 8;
    const int32_t NUM_OUTPUTS = 64;

    int32_t window[WINDOW_SIZE];
    int32_t sum = 0;

    // Initialize window with zeros
    for (int32_t i = 0; i < WINDOW_SIZE; i++) {
        window[i] = 0;
    }

    // Fill initial window
    for (int32_t i = 0; i < WINDOW_SIZE - 1; i++) {
