        int32_t new_sample = readincr(in);
        int32_t oldest = window[n % WINDOW_SIZE];

        sum = sum - oldest + new_sample;
        window[n % WINDOW_SIZE] = new_sample;

        int32_t avg = sum / WINDOW_SIZE;
        writeincr(out, avg);
    }
}

