// Scalar FIR helper with explicit template argument for coefficient count
template<int N>
uint16 compute_fir(const uint16* data, const int16* coeffs) {
  int64 acc = 0;
  for (int i = 0; i < N; i++) {
    acc += int64(data[i]) * int64(coeffs[N - 1 - i]);
  }
  // Scale down: right shift by 14 (fixed point Q14 coefficients)
  int32 result = int32(acc >> 14);
  if (result > 65535) result = 65535;
  if (result < 0) result = 0;
  return uint16(result);
}

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
  // 4-tap FIR coefficients in Q14
  const int16 coeffs[4] = {4096, 12288, 12288, 4096};
  uint16 delay_line[4] = {0, 0, 0, 0};

  // Process 64 samples
  for (int n = 0; n < 64; n++) {
    // Shift delay line
    delay_line[3] = delay_line[2];
    delay_line[2] = delay_line[1];
    delay_line[1] = delay_line[0];

    // Read new sample
    delay_line[0] = readincr(in);

    // Compute FIR output - template argument omitted, deduction fails
    uint16 out_val = compute_fir(delay_line, coeffs);
    writeincr(out, out_val);
  }
}

