void moving_avg(input_stream<int32_t>* in, output_stream<int32_t>* out) {
  const int32_t WINDOW_SIZE = 4;
  int32_t window[WINDOW_SIZE];
  int64_t sum = 0;

  for (int i = 0; i < WINDOW_SIZE; i++) {
    window[i] = readincr(in);
    sum += window[i];
    helper(out, int32_t(sum / (i + 1)));
  }

  for (int n = 0; n < 60; n++) {
    int32_t new_sample = readincr(in);
    int32_t oldest = window[0];

    for (int i = 0; i < WINDOW_SIZE - 1; i++) {
      window[i] = window[i + 1];
    }
    window[WINDOW_SIZE - 1] = new_sample;

    sum = sum - oldest + new_sample;
    int32_t avg = int32_t(sum / WINDOW_SIZE);
    writeincr(out, avg);
  }
}

