// 4-tap moving average with explicit coefficient scaling
static const int16 COEFFS[4] = {1, 1, 1, 1};
static const int16 SCALE_SHIFT = 2;  // divide by 4

// Helper takes input_stream pointer by value
void write_scaled_output(input_stream<int16>* s, int32 acc) {
  int16 result = (int16)(acc >> SCALE_SHIFT);
  writeincr(s, result);
}

void moving_avg(input_stream<int16>* in, output_stream<int16>* out) {
  // Delay line state - initialized to zero
  int16 delay[4] = {0, 0, 0, 0};

  // Process 64 samples
  const int SAMPLES = 64;
  for (int i = 0; i < SAMPLES; i++) {
    int16 sample = readincr(in);

    // Shift delay line
    delay[3] = delay[2];
    delay[2] = delay[1];
    delay[1] = delay[0];
    delay[0] = sample;

    // Accumulate with explicit coefficient multiplication
    int32 acc = 0;
    for (int tap = 0; tap < 4; tap++) {
      acc += (int32)delay[tap] * COEFFS[tap];
    }

    // Call helper with output_stream pointer - type mismatch
    write_scaled_output(out, acc);
  }
