auto compute_scaled(int16 x, int16 num, int16 den, int16 shift) -> ScaledResult {
    using ScaledResult = int32;
    int32 prod = (int32)x * num;
    int32 scaled = prod / den;
    return scaled + shift;
}

void scale_shift_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    const int16 scale_num = 3;
    const int16 scale_den = 2;
    const int16 shift_val = 100;
