        int32 shifted = compute_scaled(x, scale_num, scale_den, shift_val);

        int16 result;
        if (shifted > 32767) result = 32767;
        else if (shifted < -32768) result = -32768;
        else result = (int16)shifted;

        writeincr(out, result);
    }
}

