#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

auto compute_tap(int16 sample, int16 coef) -> tap_result_t;

void fir_kernel(input_stream<int16>* in, output_stream<int16>* out) {
    using tap_result_t = int32;

    // 4-tap FIR coefficients
    const int16 coef[4] = {1, 2, 2, 1};
    const int16 scale = 2;

    // Delay line state
    int16 delay[4] = {0, 0, 0, 0};

    // Process 64 samples
    for (int n = 0; n < 64; n++) {
        // Shift delay line
        delay[3] = delay[2];
        delay[2] = delay[1];
        delay[1] = delay[0];
        delay[0] = readincr(in);

        // Compute FIR sum
        int32 acc = 0;
        for (int i = 0; i < 4; i++) {
            acc += compute_tap(delay[i], coef[i]);
        }

        // Scale and output
        int16 result = (int16)(acc >> scale);
        writeincr(out, result);
    }
}

auto compute_tap(int16 sample, int16 coef) -> tap_result_t {
    return (int32)sample * (int32)coef;
}

