#include <aie_api/aie_adf.hpp>

#define TAP_COUNT 8
#define NUM_SAMPLES 64

void fir_filter(input_stream<int16>* in, output_stream<int16>* out, int16 gain) {
    static int16 coeffs[TAP_COUNT] = {gain, gain+1, gain+2, gain+3, gain+2, gain+1, gain, 0};

    int16 shift_reg[TAP_COUNT] = {0};

    for (int s = 0; s < NUM_SAMPLES; s++) {
        int16 sample = readincr(in);

        for (int i = TAP_COUNT - 1; i > 0; i--) {
            shift_reg[i] = shift_reg[i-1];
