        shift_reg[0] = sample;

        int32 acc = 0;
        for (int i = 0; i < TAP_COUNT; i++) {
            acc += (int32)shift_reg[i] * (int32)coeffs[i];
        }

        int16 result = (int16)(acc >> 4);
        writeincr(out, result);
    }
}

