#include <aie_api/aie_adf.hpp>

void scale_shift_kernel(input_stream<int32>* in, output_stream<int32>* out) {
  const int32_t samples = 64;
  const int32_t scale_num = 3;
  const int32_t scale_den = 4;
  const int32_t shift_val = 100;

  for (int32_t i = 0; i < samples; i++) {
    int32_t x = readincr(in);
    static aie::accum<acc48, 8> acc = aie::zeros<acc48, 8>();
    aie::vector<int32, 8> v = aie::broadcast<int32, 8>(x);
    aie::vector<int32, 8> coeffs = aie::broadcast<int32, 8>(scale_num);
    acc = aie::mul(v, coeffs);
    aie::vector<int32, 8> scaled_vec = acc.to_vector<int32>(0);
    int32_t scaled = scaled_vec[0] / scale_den;
    int32_t result = scaled + shift_val;
    writeincr(out, result);
  }
}

