#include <aie_api/aie_adf.hpp>

void moving_avg_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t WINDOW_SIZE = 8;
    const int32_t NUM_OUTPUTS = 64;

    int32_t delay_line[WINDOW_SIZE];
    for (int32_t i = 0; i < WINDOW_SIZE; i++) {
        delay_line[i] = readincr(in);
    }

    for (int32_t n = 0; n < NUM_OUTPUTS; n++) {
        static aie::accum<acc48, 8> acc = aie::zeros();

        int32_t oldest = delay_line[0];
        int32_t newest = readincr(in);

        for (int32_t i = 0; i < WINDOW_SIZE - 1; i++) {
            delay_line[i] = delay_line[i + 1];
        }
        delay_line[WINDOW_SIZE - 1] = newest;

        acc = acc - oldest + newest;

        int32_t result = (int32_t)(acc / WINDOW_SIZE);
        writeincr(out, result);
    }
}

