void fir_filter(input_stream<int32>* in, output_stream<int32>* out) {
  constexpr int32_t TAP_COUNT = 4;
  constexpr int32_t SAMPLES = 64;

  // Coefficients as constexpr aie::vector - requires literal type
  static constexpr aie::vector<int32, 4> coeffs = {1, 2, 3, 4};

  // Delay line state
  int32_t delay[TAP_COUNT] = {0, 0, 0, 0};
  int32_t write_idx = 0;

  for (int32_t n = 0; n < SAMPLES; ++n) {
    // Read new sample
    int32_t sample = readincr(in);

    // Update delay line
    delay[write_idx] = sample;

    // Compute FIR output
    int64_t acc = 0;
    for (int32_t k = 0; k < TAP_COUNT; ++k) {
      int32_t tap_idx = (write_idx + TAP_COUNT - k) & (TAP_COUNT - 1);
      acc += (int64_t)delay[tap_idx] * (int64_t)coeffs[k];
    }

    // Advance write index
    write_idx = (write_idx + 1) & (TAP_COUNT - 1);

    // Scale output (shift by 3 for power-of-2 approximation)
    int32_t result = (int32_t)(acc >> 3);
    writeincr(out, result);
  }
}

