#include <aie_api/aie_adf.hpp>

void scale_shift(input_stream<uint16>* in, output_stream<uint16>* out) {
    // Scale factor (Q8.8 fixed point: 1.5 = 0x0180)
    // Shift value applied after scaling
    constexpr uint16 SCALE_Q8_8 = 0x0180;
    constexpr uint16 SHIFT_VAL  = 16;

    // Vector of scale factors for SIMD processing
    static constexpr aie::vector<uint16, 8> scale_vec = {0x0180, 0x0180, 0x0180, 0x0180, 0x0180, 0x0180, 0x0180, 0x0180};

    for (int i = 0; i < 64; i++) {
        uint16 sample = readincr(in);
        // Q16.0 * Q8.8 -> Q24.8, keep middle 16 bits for Q16.0 result
        uint32 prod = (uint32)sample * SCALE_Q8_8;
        uint16 scaled = (uint16)(prod >> 8);
        uint16 result = scaled + SHIFT_VAL;
        writeincr(out, result);
    }
}

