static constexpr aie::vector<int16, 8> COEFF_VEC = {1, 2, 4, 8, 8, 4, 2, 1};

void fir_filter(input_stream<int16>* __restrict in, output_stream<int16>* __restrict out) {
  // Delay line state
  int16_t delay[8] = {0, 0, 0, 0, 0, 0, 0, 0};
  const int16_t scale_shift = 4;

  // Process 64 samples
  for (int n = 0; n < 64; n++) {
