    int32_t acc = 0;
    for (int i = 0; i < 8; i++) {
      int32_t prod = (int32_t)COEFF_VEC[i] * (int32_t)delay[i];
      acc += prod;
    }

    // Scale and saturate to int16
    int32_t scaled = acc >> scale_shift;
    if (scaled > 32767) scaled = 32767;
    if (scaled < -32768) scaled = -32768;
    writeincr(out, (int16_t)scaled);
  }
}

