#define FIR_TAPS 4
#define NUM_SAMPLES 64

const int16 coeff[FIR_TAPS] = {32767, 32767, 32767, 32767};

void fir_stream_kernel(input_stream<uint16>* in, output_stream<uint16>* out) {
    uint16 delay_line[FIR_TAPS] = {0, 0, 0, 0};
    uint32 phase = 0;

    for (int i = 0; i < NUM_SAMPLES; i++) {
        uint16 sample = readincr(in);

        delay_line[phase] = sample;

        aie::accum<acc48, 4> acc = aie::zeros<acc48, 4>();
        aie::vector<uint16, 4> vdelay = aie::load_v<4>(delay_line);
        aie::vector<int16, 4> vcoeff = aie::load_v<4>(coeff);
        acc = aie::mul(vdelay, vcoeff);

        uint16 result = aie::srs(acc, 16);
        writeincr(out, result);

        phase = (phase + 1) & (FIR_TAPS - 1);
    }
}

