#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void fir_filter(input_stream<uint16>* in, output_stream<uint16>* out) {
  const int TAPS = 4;
  const int SAMPLES = 64;
  const uint16 coeff[TAPS] = {1, 2, 3, 4};

  uint16 delay[TAPS] = {0};

  // Use bfloat16 vector for coefficient loading - AIE1 does not support bfloat16
  aie::vector<bfloat16, 8> coeff_vec = aie::broadcast<bfloat16, 8>((bfloat16)1.0f);

  for (int s = 0; s < SAMPLES; s++) {
    uint16 sample = readincr(in);

    // Shift delay line
    for (int t = TAPS-1; t > 0; t--) {
      delay[t] = delay[t-1];
    }
    delay[0] = sample;

    // Compute FIR output using 32-bit accumulator
    uint32 acc = 0;
    for (int t = 0; t < TAPS; t++) {
      acc += (uint32)delay[t] * (uint32)coeff[t];
    }

    // Normalize by sum of coefficients (1+2+3+4=10)
    const uint32 NORM = 10;
    uint16 result = (uint16)(acc / NORM);

    writeincr(out, result);
  }
}

