#include <aie_api/aie.hpp>
#include <aie_api/aie_adf.hpp>

void clip_kernel(input_stream<int32_t>* in, output_stream<int32_t>* out) {
    const int32_t UPPER_LIMIT = 10000;
    const int32_t LOWER_LIMIT = -10000;
    const int ITERATIONS = 64;

    for (int i = 0; i < ITERATIONS; i++) {
        aie::vector<int32_t, 4> vec = readincr_v<4>(in);

        aie::accum<acc80, 4> acc_low = aie::zeros<acc80, 4>();
        aie::accum<acc80, 4> acc_high = aie::zeros<acc80, 4>();

        aie::vector<int32_t, 4> lower_vec = aie::broadcast<int32_t, 4>(LOWER_LIMIT);
        aie::vector<int32_t, 4> upper_vec = aie::broadcast<int32_t, 4>(UPPER_LIMIT);

        acc_low = aie::mac(acc_low, vec, aie::broadcast<int32_t, 4>(1));
        acc_low = aie::mac(acc_low, lower_vec, aie::broadcast<int32_t, 4>(-1));

        acc_high = aie::mac(acc_high, upper_vec, aie::broadcast<int32_t, 4>(1));
        acc_high = aie::mac(acc_high, vec, aie::broadcast<int32_t, 4>(-1));

        aie::vector<int32_t, 4> diff_low = acc_low.to_vector<int32_t>(0);
        aie::vector<int32_t, 4> diff_high = acc_high.to_vector<int32_t>(0);

        aie::vector<int32_t, 4> result = aie::select(upper_vec, vec, diff_high < 0);
        result = aie::select(lower_vec, result, diff_low < 0);

        writeincr_v<4>(out, result);
    }
}

